1	-------------------------------------------------------------------------------
2	-- Title      : RSSI Protocol: https://confluence.slac.stanford.edu/x/1IyfD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: Connection establishment mechanism:
7	--                - Connection open/close request,
8	--                - Parameter negotiation,
9	--                - Server-client mode (More comments below).
10	-------------------------------------------------------------------------------
11	-- This file is part of 'SLAC Firmware Standard Library'.
12	-- It is subject to the license terms in the LICENSE.txt file found in the
13	-- top-level directory of this distribution and at:
14	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
15	-- No part of 'SLAC Firmware Standard Library', including this file,
16	-- may be copied, modified, propagated, or distributed except according to
17	-- the terms contained in the LICENSE.txt file.
18	-------------------------------------------------------------------------------
19	
20	library ieee;
21	use ieee.std_logic_1164.all;
22	use ieee.std_logic_unsigned.all;
23	use ieee.std_logic_arith.all;
24	
25	
26	library surf;
27	use surf.StdRtlPkg.all;
28	use surf.RssiPkg.all;
29	
30	entity RssiConnFsm is
31	   generic (
32	      TPD_G               : time     := 1 ns;
33	      SERVER_G            : boolean  := true;
34	      --
35	      TIMEOUT_UNIT_G      : real     := 1.0E-6;  -- us
36	      CLK_FREQUENCY_G     : real     := 100.0E6;
37	      -- Time the module waits for the response until it retransmits SYN segment
38	      RETRANS_TOUT_G      : positive := 50;
39	      MAX_RETRANS_CNT_G   : positive := 2;
40	      --
41	      WINDOW_ADDR_SIZE_G  : positive := 3;
42	      SEGMENT_ADDR_SIZE_G : positive := 7  -- 2^SEGMENT_ADDR_SIZE_G = Number of 64 bit wide data words
43	      );
44	   port (
45	      clk_i : in sl;
46	      rst_i : in sl;
47	
48	      -- Connection request (open/close)
49	      connRq_i  : in sl;
50	      closeRq_i : in sl;
51	
52	      -- Parameters received from peer (Server)
53	      rxRssiParam_i : in RssiParamType;
54	
55	      -- Parameters set by high level App or generic (Client)
56	      appRssiParam_i : in RssiParamType;
57	
58	      -- Negotiated parameters
59	      rssiParam_o : out RssiParamType;
60	
61	      -- Flags from Rx module
62	      rxFlags_i : in FlagsType;
63	
64	      -- Valid received packet
65	      rxValid_i : in sl;
66	
67	      synHeadSt_i : in sl;
68	      ackHeadSt_i : in sl;
69	      rstHeadSt_i : in sl;
70	
71	      --
72	      -- Connection FSM indicating active connection
73	      connActive_o : out sl;
74	
75	      -- FSM in closed state (indicating when to initialize seqN)
76	      closed_o : out sl;
77	
78	      --
79	      sndSyn_o : out sl;
80	      sndAck_o : out sl;
81	      sndRst_o : out sl;
82	      txAckF_o : out sl;
83	      --
84	
85	      -- Window size and buffer size different for Rx and Tx
86	      rxBufferSize_o : out integer range 1 to 2 ** (SEGMENT_ADDR_SIZE_G);
87	      rxWindowSize_o : out integer range 1 to 2 ** (WINDOW_ADDR_SIZE_G);
88	      --
89	      txBufferSize_o : out integer range 1 to 2 ** (SEGMENT_ADDR_SIZE_G);
90	      txWindowSize_o : out integer range 1 to 2 ** (WINDOW_ADDR_SIZE_G);
91	
92	      -- Debug
93	      connState_o : out slv(3 downto 0);
94	
95	      -- Status signals
96	      peerTout_o    : out sl;
97	      paramReject_o : out sl
98	      );
99	end entity RssiConnFsm;
100	
101	architecture rtl of RssiConnFsm is
102	   --
103	   constant SAMPLES_PER_TIME_C : integer := integer(TIMEOUT_UNIT_G * CLK_FREQUENCY_G);
104	   --
105	   type StateType is (
106	      CLOSED_S,
107	      SEND_SYN_S,
108	      WAIT_SYN_S,
109	      LISTEN_S,
110	      SEND_ACK_S,
111	      SEND_SYN_ACK_S,
112	      WAIT_ACK_S,
113	      SEND_RST_S,
114	      OPEN_S
115	      );
116	
117	   type RegType is record
118	      connActive  : sl;
119	      closed      : sl;
120	      sndSyn      : sl;
121	      sndAck      : sl;
122	      sndRst      : sl;
123	      txAckF      : sl;
124	      peerTout    : sl;
125	      paramReject : sl;
126	
127	      rssiParam : RssiParamType;
128	
129	      --
130	      txBufferSize : integer range 1 to 2 ** (SEGMENT_ADDR_SIZE_G);
131	      txWindowSize : integer range 1 to 2 ** (WINDOW_ADDR_SIZE_G);
132	      --
133	      timeoutCntr  : integer range 0 to RETRANS_TOUT_G * SAMPLES_PER_TIME_C;
134	      resendCntr   : integer range 0 to MAX_RETRANS_CNT_G+1;
135	
136	      ---
137	      state     : StateType;
138	      connState : slv(3 downto 0);
139	
140	   end record RegType;
141	
142	   constant REG_INIT_C : RegType := (
143	      connActive  => '0',
144	      closed      => '1',
145	      sndSyn      => '0',
146	      sndAck      => '0',
147	      sndRst      => '0',
148	      txAckF      => '0',
149	      peerTout    => '0',
150	      paramReject => '0',
151	
152	      rssiParam => RSSI_PARAM_INIT_C,
153	
154	      timeoutCntr  => 0,
155	      resendCntr   => 0,
156	      --
157	      txBufferSize => 1,
158	      txWindowSize => 1,
159	
160	      ---
161	      state     => CLOSED_S,
162	      connState => (others => '0')
163	      );
164	
165	   signal r   : RegType := REG_INIT_C;
166	   signal rin : RegType;
167	
168	
169	
170	begin
171	
172	   comb : process (ackHeadSt_i, appRssiParam_i, closeRq_i, connRq_i, r,
173	                   rstHeadSt_i, rst_i, rxFlags_i, rxRssiParam_i, rxValid_i,
174	                   synHeadSt_i) is
175	      variable v : RegType;
176	   begin
177	      v := r;
178	
179	      -- /////////////////////////////////////////////////////////
180	      ------------------------------------------------------------
181	      -- Connection FSM
182	      -- Synchronization and parameter negotiation
183	      ------------------------------------------------------------
184	      -- /////////////////////////////////////////////////////////
185	
186	      case r.state is
187	         ----------------------------------------------------------------------
188	         when CLOSED_S =>
189	            v.connState := x"0";
190	
191	            -- Initialize parameters
192	            v := REG_INIT_C;
193	
194	            -- Next state condition
195	            -- Initiated by high level App and depends on whether it is a
196	            -- server or client.
197	            if (connRq_i = '1' and SERVER_G = true) then
198	               v.state := LISTEN_S;     -- Server Passive open
199	            elsif (connRq_i = '1' and SERVER_G = false) then
200	               v.state := SEND_SYN_S;   -- Client Active open
201	            end if;
202	         ----------------------------------------------------------------------
203	         -- Client
204	         --  Actively open connection
205	         --  Propose parameters
206	         --  Accept parameters from server or close connection
207	         ----------------------------------------------------------------------
208	         when SEND_SYN_S =>
209	            v.connState := x"1";
210	
211	            v.connActive  := '0';
212	            v.closed      := '0';
213	            v.sndSyn      := '1';
214	            v.sndAck      := '0';
215	            v.sndRst      := '0';
216	            v.txAckF      := '0';
217	            v.peerTout    := '0';
218	            v.paramReject := '0';
219	            v.timeoutCntr := 0;
220	
221	            -- Send the Client proposed parameters
222	            v.rssiParam := appRssiParam_i;
223	
224	            if (synHeadSt_i = '1') then
225	               v.state := WAIT_SYN_S;
226	            end if;
227	
228	         ----------------------------------------------------------------------
229	         when WAIT_SYN_S =>
230	            v.connState := x"2";
231	
232	            v.connActive  := '0';
233	            v.sndSyn      := '0';
234	            v.sndAck      := '0';
235	            v.sndRst      := '0';
236	            v.txAckF      := '0';
237	            v.timeoutCntr := r.timeoutCntr + 1;
238	            --
239	            if (rxValid_i = '1' and rxFlags_i.syn = '1' and rxFlags_i.ack = '1') then
240	               -- Check parameters
241	               if (
242	                  rxRssiParam_i.version = appRssiParam_i.version and  -- Version match
243	                  rxRssiParam_i.chksumEn = appRssiParam_i.chksumEn and  -- Checksum match
244	                  rxRssiParam_i.timeoutUnit = appRssiParam_i.timeoutUnit  -- Timeout unit match
245	                  ) then
246	
247	                  -- Accept the parameters from the server
248	                  v.rssiParam := rxRssiParam_i;
249	
250	                  -- Autoneg the maxOutsSeg
251	                  if (rxRssiParam_i.maxOutsSeg > appRssiParam_i.maxOutsSeg) then
252	                     v.txWindowSize         := conv_integer(appRssiParam_i.maxOutsSeg);
253	                     v.rssiParam.maxOutsSeg := appRssiParam_i.maxOutsSeg;
254	                  else
255	                     v.txWindowSize         := conv_integer(rxRssiParam_i.maxOutsSeg);
256	                     v.rssiParam.maxOutsSeg := rxRssiParam_i.maxOutsSeg;
257	                  end if;
258	
259	                  -- Autoneg the maxSegSize
260	                  if (rxRssiParam_i.maxSegSize > appRssiParam_i.maxSegSize) then
261	                     v.txBufferSize         := conv_integer(appRssiParam_i.maxSegSize(15 downto 3));  -- Divide by 8
262	                     v.rssiParam.maxSegSize := appRssiParam_i.maxSegSize;
263	                  else
264	                     v.txBufferSize         := conv_integer(rxRssiParam_i.maxSegSize(15 downto 3));  -- Divide by 8
265	                     v.rssiParam.maxSegSize := rxRssiParam_i.maxSegSize;
266	                  end if;
267	
268	                  --
269	                  v.state := SEND_ACK_S;
270	               else
271	                  -- Reject parameters and reset the connection
272	                  v.paramReject := '1';
273	                  v.rssiParam   := r.rssiParam;
274	                  --
275	                  v.state       := SEND_RST_S;
276	               end if;
277	            elsif (rxValid_i = '1' and rxFlags_i.rst = '1') then
278	               v.state := CLOSED_S;
279	            elsif (r.timeoutCntr = RETRANS_TOUT_G * SAMPLES_PER_TIME_C) then
280	               if (r.resendCntr >= MAX_RETRANS_CNT_G) then
281	                  v.peerTout := '1';
282	                  v.state    := CLOSED_S;
283	               else
284	                  v.closed     := '1';  -- Signal closed to reset seqN (Resend SYN with the initial seqN)
285	                  v.resendCntr := r.resendCntr + 1;
286	                  v.state      := SEND_SYN_S;
287	               end if;
288	            end if;
289	         ----------------------------------------------------------------------
290	         when SEND_ACK_S =>
291	            v.connState := x"3";
292	
293	            v.connActive  := '0';
294	            v.sndSyn      := '0';
295	            v.sndAck      := '1';
296	            v.sndRst      := '0';
297	            v.txAckF      := '1';
298	            v.timeoutCntr := 0;
299	            v.resendCntr  := 0;
300	            v.paramReject := '0';
301	            --
302	            v.rssiParam   := r.rssiParam;
303	
304	            --
305	            if (ackHeadSt_i = '1') then
306	               v.state := OPEN_S;
307	            end if;
308	
309	         ----------------------------------------------------------------------
310	         -- Server
311	         --  Passively open connection. Go to listen state and wait for SYN.
312	         --  Check clients parameters:
313	         --         If valid accept parameters,
314	         --         If not valid propose new parameters.
315	         ----------------------------------------------------------------------
316	         when LISTEN_S =>
317	            v.connState := x"4";
318	
319	            v.connActive  := '0';
320	            v.closed      := '0';
321	            v.sndSyn      := '0';
322	            v.sndAck      := '0';
323	            v.sndRst      := '0';
324	            v.txAckF      := '0';
325	            v.peerTout    := '0';
326	            v.timeoutCntr := 0;
327	            --
328	            if (rxValid_i = '1' and rxFlags_i.syn = '1') then
329	
330	               -- Accept the parameters from the client
331	               v.rssiParam := rxRssiParam_i;
332	
333	               -- Autoneg the maxOutsSeg
334	               if (rxRssiParam_i.maxOutsSeg > appRssiParam_i.maxOutsSeg) then
335	                  v.txWindowSize         := conv_integer(appRssiParam_i.maxOutsSeg);
336	                  v.rssiParam.maxOutsSeg := appRssiParam_i.maxOutsSeg;
337	               else
338	                  v.txWindowSize         := conv_integer(rxRssiParam_i.maxOutsSeg);
339	                  v.rssiParam.maxOutsSeg := rxRssiParam_i.maxOutsSeg;
340	               end if;
341	
342	               -- Autoneg the maxSegSize
343	               if (rxRssiParam_i.maxSegSize > appRssiParam_i.maxSegSize) then
344	                  v.txBufferSize         := conv_integer(appRssiParam_i.maxSegSize(15 downto 3));  -- Divide by 8
345	                  v.rssiParam.maxSegSize := appRssiParam_i.maxSegSize;
346	               else
347	                  v.txBufferSize         := conv_integer(rxRssiParam_i.maxSegSize(15 downto 3));  -- Divide by 8
348	                  v.rssiParam.maxSegSize := rxRssiParam_i.maxSegSize;
349	               end if;
350	
351	               --
352	               v.paramReject := '0';
353	
354	               -- Check parameters that have to match
355	               if (
356	                  rxRssiParam_i.version /= appRssiParam_i.version or  -- Version equality
357	                  rxRssiParam_i.chksumEn /= appRssiParam_i.chksumEn or  -- Checksum match
358	                  rxRssiParam_i.timeoutUnit /= appRssiParam_i.timeoutUnit  -- Timeout unit match
359	                  ) then
360	
361	                  -- Propose different parameters (overwrite)
362	                  v.rssiParam.version     := appRssiParam_i.version;
363	                  v.rssiParam.timeoutUnit := appRssiParam_i.timeoutUnit;
364	                  v.rssiParam.chksumEn    := appRssiParam_i.chksumEn;
365	                  --
366	                  v.paramReject           := '1';
367	               end if;
368	               -- Go to ACK state
369	               v.state := SEND_SYN_ACK_S;
370	            end if;
371	         ---------------------------------------------------------------------
372	         when SEND_SYN_ACK_S =>
373	            v.connState := x"5";
374	
375	            v.connActive  := '0';
376	            v.closed      := '0';
377	            v.sndSyn      := '1';
378	            v.sndAck      := '0';
379	            v.sndRst      := '0';
380	            v.txAckF      := '1';
381	            v.paramReject := '0';
382	            v.timeoutCntr := 0;
383	
384	            -- Send the Server parameters
385	            v.rssiParam := r.rssiParam;
386	
387	            if (synHeadSt_i = '1') then
388	               v.state := WAIT_ACK_S;
389	            end if;
390	
391	         when WAIT_ACK_S =>
392	            v.connState := x"6";
393	
394	            v.connActive  := '0';
395	            v.sndSyn      := '0';
396	            v.sndAck      := '0';
397	            v.sndRst      := '0';
398	            v.txAckF      := '0';
399	            v.paramReject := '0';
400	            --
401	            v.timeoutCntr := r.timeoutCntr+1;
402	
403	            --
404	            v.rssiParam := r.rssiParam;
405	
406	            if (rxValid_i = '1' and rxFlags_i.ack = '1') then
407	               v.state := OPEN_S;
408	            elsif (rxValid_i = '1' and rxFlags_i.rst = '1') then
409	               v.state := CLOSED_S;
410	            elsif (r.timeoutCntr = RETRANS_TOUT_G * SAMPLES_PER_TIME_C) then
411	               if (r.resendCntr >= MAX_RETRANS_CNT_G) then
412	                  v.peerTout := '1';
413	                  v.state    := CLOSED_S;
414	               else
415	                  v.closed     := '1';  -- Signal closed to reset seqN (Resend SYN with the initial seqN)
416	                  v.resendCntr := r.resendCntr + 1;
417	                  v.state      := SEND_SYN_ACK_S;
418	               end if;
419	            end if;
420	
421	         ----------------------------------------------------------------------
422	         -- Open connection
423	         --
424	         --
425	         ----------------------------------------------------------------------
426	         when OPEN_S =>
427	            v.connState := x"7";
428	
429	            v.connActive  := '1';
430	            v.sndSyn      := '0';
431	            v.sndAck      := '0';
432	            v.sndRst      := '0';
433	            v.txAckF      := '1';
434	            v.paramReject := '0';
435	            --
436	            v.timeoutCntr := 0;
437	            v.resendCntr  := 0;
438	            --
439	            v.rssiParam   := r.rssiParam;
440	
441	            --
442	            if (rxValid_i = '1' and rxFlags_i.rst = '1') then
443	               v.state := SEND_RST_S;
444	            elsif (closeRq_i = '1') then
445	               v.state := SEND_RST_S;
446	            end if;
447	
448	         ----------------------------------------------------------------------
449	         -- Reset the connection
450	         -- - Send Rst segment
451	         -- - Go to Closed
452	         ----------------------------------------------------------------------
453	         when SEND_RST_S =>
454	            v.connState := x"8";
455	
456	            v.connActive  := r.connActive;
457	            v.sndSyn      := '0';
458	            v.sndAck      := '0';
459	            v.sndRst      := '1';
460	            v.txAckF      := '0';
461	            v.paramReject := '0';
462	            --
463	            v.rssiParam   := r.rssiParam;
464	
465	            --
466	            if (rstHeadSt_i = '1') then
467	               v.state := CLOSED_S;
468	            end if;
469	
470	         ----------------------------------------------------------------------
471	         when others =>
472	            v := REG_INIT_C;
473	      ----------------------------------------------------------------------
474	      end case;
475	
476	      if (rst_i = '1') then
477	         v := REG_INIT_C;
478	      end if;
479	
480	      rin <= v;
481	   -----------------------------------------------------------
482	   end process comb;
483	
484	   seq : process (clk_i) is
485	   begin
486	      if (rising_edge(clk_i)) then
487	         r <= rin after TPD_G;
488	      end if;
489	   end process seq;
490	
491	   ------------------------------------------------------------------------------
492	   -- Output assignment
493	   rssiParam_o  <= r.rssiParam;
494	   connActive_o <= r.connActive;
495	   sndSyn_o     <= r.sndSyn;
496	   sndAck_o     <= r.sndAck;
497	   sndRst_o     <= r.sndRst;
498	   txAckF_o     <= r.txAckF;
499	
500	   -- Parameters for transmitter are received by the peer and checked by FSM
501	   rxBufferSize_o <= r.txBufferSize;
502	   rxWindowSize_o <= r.txWindowSize;
503	   txBufferSize_o <= r.txBufferSize;
504	   txWindowSize_o <= r.txWindowSize;
505	   closed_o       <= r.closed;
506	   --
507	   connState_o    <= r.connState;
508	   peerTout_o     <= r.peerTout;
509	   paramReject_o  <= r.paramReject;
510	---------------------------------------------------------------------
511	end architecture rtl;
