50	entity RssiCore is
51	   generic (
52	      TPD_G           : time := 1 ns;
53	      CLK_FREQUENCY_G : real := 100.0E6;
54	      TIMEOUT_UNIT_G  : real := 1.0E-6;  -- us (Applies to all the timeouts in the core)
55	
56	      SERVER_G : boolean := true;       -- Module is server or client
57	
58	      RETRANSMIT_ENABLE_G : boolean := true;  -- Enable/Disable retransmissions in tx module
59	
60	      WINDOW_ADDR_SIZE_G  : positive range 1 to 10 := 3;  -- 2^WINDOW_ADDR_SIZE_G  = Max number of segments in buffer
61	      SEGMENT_ADDR_SIZE_G : positive               := 7;  -- 2^SEGMENT_ADDR_SIZE_G = Number of 64 bit wide data words
62	
63	      -- AXIS Configurations
64	      APP_AXIS_CONFIG_G : AxiStreamConfigType;
65	      TSP_AXIS_CONFIG_G : AxiStreamConfigType;
66	
67	      -- Generic RSSI parameters
68	      BYP_TX_BUFFER_G : boolean := false;
69	      BYP_RX_BUFFER_G : boolean := false;
70	
71	      SYNTH_MODE_G  : string := "inferred";
72	      MEMORY_TYPE_G : string := "block";
73	
74	      -- Version and connection ID
75	      INIT_SEQ_N_G       : natural  := 16#80#;
76	      CONN_ID_G          : positive := 16#12345678#;
77	      VERSION_G          : positive := 1;
78	      HEADER_CHKSUM_EN_G : boolean  := true;
79	
80	      -- Window parameters of receiver module
81	      MAX_NUM_OUTS_SEG_G : positive range 2 to 1024 := 8;  -- <=(2**WINDOW_ADDR_SIZE_G)
82	      MAX_SEG_SIZE_G     : positive                 := 1024;  -- <= (2**SEGMENT_ADDR_SIZE_G)*8 Number of bytes
83	
84	      -- RSSI Timeouts
85	      ACK_TOUT_G     : positive := 25;  -- unit depends on TIMEOUT_UNIT_G
86	      RETRANS_TOUT_G : positive := 50;  -- unit depends on TIMEOUT_UNIT_G  (Recommended >= MAX_NUM_OUTS_SEG_G*Data segment transmission time)
87	      NULL_TOUT_G    : positive := 200;  -- unit depends on TIMEOUT_UNIT_G  (Recommended >= 4*RETRANS_TOUT_G)
88	
89	      -- Counters
90	      MAX_RETRANS_CNT_G : positive := 2;
91	      MAX_CUM_ACK_CNT_G : positive := 3
92	      );
93	   port (
94	      clk_i : in sl;
95	      rst_i : in sl;
96	
97	      -- High level  Application side interface
98	      openRq_i  : in sl;
99	      closeRq_i : in sl;
100	      inject_i  : in sl := '0';
101	
102	      -- SSI Application side
103	      sAppAxisMaster_i : in  AxiStreamMasterType;
104	      sAppAxisSlave_o  : out AxiStreamSlaveType;
105	      mAppAxisMaster_o : out AxiStreamMasterType;
106	      mAppAxisSlave_i  : in  AxiStreamSlaveType;
107	
108	      -- SSI Transport side
109	      sTspAxisMaster_i : in  AxiStreamMasterType;
110	      sTspAxisSlave_o  : out AxiStreamSlaveType;
111	      mTspAxisMaster_o : out AxiStreamMasterType;
112	      mTspAxisSlave_i  : in  AxiStreamSlaveType;
113	
114	      -- AXI-Lite Register Interface
115	      axiClk_i        : in  sl                     := '0';
116	      axiRst_i        : in  sl                     := '0';
117	      axilReadMaster  : in  AxiLiteReadMasterType  := AXI_LITE_READ_MASTER_INIT_C;
118	      axilReadSlave   : out AxiLiteReadSlaveType;
119	      axilWriteMaster : in  AxiLiteWriteMasterType := AXI_LITE_WRITE_MASTER_INIT_C;
120	      axilWriteSlave  : out AxiLiteWriteSlaveType;
121	
122	      -- Internal statuses
123	      statusReg_o : out slv(8 downto 0);
124	
125	      maxSegSize_o : out slv(15 downto 0));
126	end entity RssiCore;
