194	   signal s_rxWrBuffWe   : sl;
195	   signal s_rxRdBuffRe   : sl;
196	   signal s_rxRdBuffAddr : slv(BUFFER_ADDR_WIDTH_C-1 downto 0);
197	   signal s_rxRdBuffData : slv(RSSI_WORD_WIDTH_C*8-1 downto 0);
198	
199	   -- Tx segment buffer
200	   signal s_txBufferSize : integer range 1 to 2 ** (SEGMENT_ADDR_SIZE_G);
201	   signal s_txWindowSize : integer range 1 to 2 ** (WINDOW_ADDR_SIZE_G);
202	   signal s_txWrBuffAddr : slv(BUFFER_ADDR_WIDTH_C-1 downto 0);
