204	   signal s_txWrBuffWe   : sl;
205	   signal s_txRdBuffRe   : sl;
206	   signal s_txRdBuffAddr : slv(BUFFER_ADDR_WIDTH_C-1 downto 0);
207	   signal s_txRdBuffData : slv(RSSI_WORD_WIDTH_C*8-1 downto 0);
208	
209	   -- Acknowledge pulse when valid segment
210	   -- with acknowledge flag received
211	   signal s_rxAck : sl;
212	
213	   -- Application Fifo reset when connection is closed
214	   signal s_rstFifo : sl;
215	
216	   -- AXIS Application side
217	   signal s_sAppAxisMaster : AxiStreamMasterType;
218	   signal s_sAppAxisSlave  : AxiStreamSlaveType;
219	   signal s_mAppAxisMaster : AxiStreamMasterType;
220	   signal s_mAppAxisSlave  : AxiStreamSlaveType;
221	   signal s_mAppAxisCtrl   : AxiStreamCtrlType;
222	   signal s_mAppfifoWrCnt  : slv(SEGMENT_ADDR_SIZE_G downto 0);
