240	   signal s_mTspSsiMaster : SsiMasterType;
241	   signal s_mTspSsiSlave  : SsiSlaveType;
242	
243	   -- Monitor input signals
244	   signal s_txBufferEmpty : sl;
245	   signal s_lenErr        : sl;
246	   signal s_ackErr        : sl;
247	   signal s_peerConnTout  : sl;
248	   signal s_paramReject   : sl;
