250	   -- Connection control and parameters
251	   signal s_initSeqN   : slv(7 downto 0);
252	   signal s_connActive : sl;
253	   signal s_closeRq    : sl;
254	   signal s_closed     : sl;
255	   signal s_openRq     : sl;
256	   signal s_intCloseRq : sl;
257	   signal s_txAckF     : sl;
258	
259	   -- Fault injection
