306	   AxiLiteRegItf_INST : entity surf.RssiAxiLiteRegItf
307	      generic map (
308	         TPD_G                 => TPD_G,
309	         TIMEOUT_UNIT_G        => TIMEOUT_UNIT_G,
310	         SEGMENT_ADDR_SIZE_G   => SEGMENT_ADDR_SIZE_G,
311	         INIT_SEQ_N_G          => INIT_SEQ_N_G,
312	         CONN_ID_G             => CONN_ID_G,
313	         VERSION_G             => VERSION_G,
314	         HEADER_CHKSUM_EN_G    => HEADER_CHKSUM_EN_G,
315	         MAX_NUM_OUTS_SEG_G    => MAX_NUM_OUTS_SEG_G,
316	         MAX_SEG_SIZE_G        => MAX_SEG_SIZE_G,
317	         RETRANS_TOUT_G        => RETRANS_TOUT_G,
318	         ACK_TOUT_G            => ACK_TOUT_G,
319	         NULL_TOUT_G           => NULL_TOUT_G,
320	         MAX_RETRANS_CNT_G     => MAX_RETRANS_CNT_G,
321	         MAX_CUM_ACK_CNT_G     => MAX_CUM_ACK_CNT_G,
322	         MAX_OUT_OF_SEQUENCE_G => 0)
323	      port map (
324	         axiClk_i        => axiClk_i,
325	         axiRst_i        => axiRst_i,
326	         axilReadMaster  => axilReadMaster,
327	         axilReadSlave   => axilReadSlave,
328	         axilWriteMaster => axilWriteMaster,
329	         axilWriteSlave  => axilWriteSlave,
330	
331	         -- DevClk domain
332	         devClk_i => clk_i,
333	         devRst_i => rst_i,
334	
335	         -- Control
336	         openRq_o       => s_openRqReg,
337	         closeRq_o      => s_closeRqReg,
338	         mode_o         => s_modeReg,
339	         initSeqN_o     => s_initSeqNReg,
340	         appRssiParam_o => s_appRssiParamReg,
341	         negRssiParam_i => s_rssiParam,
342	         injectFault_o  => s_injectFaultReg,
343	
344	         -- Status (RO)
345	         txLastAckN_i => s_rxLastAckN,
346	         rxSeqN_i     => s_rxLastSeqN,
347	         rxAckN_i     => s_rxAckN,
348	         rxLastSeqN_i => s_rxLastSeqN,
349	         txTspState_i => s_txTspState,
350	         txAppState_i => s_txAppState,
351	         txAckState_i => s_txAckState,
352	         rxTspState_i => s_rxTspState,
353	         rxAppState_i => s_rxAppState,
354	         connState_i  => s_connState,
355	         frameRate_i  => frameRate,
356	         bandwidth_i  => bandwidth,
357	         status_i     => s_statusReg,
358	         dropCnt_i    => s_dropCntReg,
359	         validCnt_i   => s_validCntReg,
360	         resendCnt_i  => s_resendCntReg,
361	         reconCnt_i   => s_reconCntReg);
