365	   -- /////////////////////////////////////////////////////////
366	   ------------------------------------------------------------
367	   -- Parameter assignment
368	   ------------------------------------------------------------
369	   -- /////////////////////////////////////////////////////////
370	   combParamAssign : process (closeRq_i, openRq_i, s_appRssiParamReg,
371	                              s_closeRqReg, s_initSeqNReg, s_intCloseRq,
372	                              s_modeReg, s_openRqReg) is
373	   begin
374	      if (s_modeReg = '0') then
375	         -- Use external requests
376	         s_closeRq <= s_closeRqReg or closeRq_i or s_intCloseRq;
377	         s_openRq  <= s_openRqReg or openRq_i;
378	
379	         -- Assign application side Rssi parameters from generics
380	         s_appRssiParam.maxOutsSeg   <= toSlv(MAX_NUM_OUTS_SEG_G, 8);
381	         s_appRssiParam.maxSegSize   <= toSlv(MAX_SEG_SIZE_G, 16);
382	         s_appRssiParam.retransTout  <= toSlv(RETRANS_TOUT_G, 16);
383	         s_appRssiParam.cumulAckTout <= toSlv(ACK_TOUT_G, 16);
384	         s_appRssiParam.nullSegTout  <= toSlv(NULL_TOUT_G, 16);
385	         s_appRssiParam.maxRetrans   <= toSlv(MAX_RETRANS_CNT_G, 8);
386	         s_appRssiParam.maxCumAck    <= toSlv(MAX_CUM_ACK_CNT_G, 8);
387	         s_appRssiParam.maxOutofseq  <= toSlv(0, 8);
388	         s_appRssiParam.version      <= toSlv(VERSION_G, 4);
389	         s_appRssiParam.connectionId <= toSlv(CONN_ID_G, 32);
390	         s_appRssiParam.chksumEn     <= ite(HEADER_CHKSUM_EN_G, "1", "0");
391	         s_appRssiParam.timeoutUnit  <= toSlv(integer(0.0 - (ieee.math_real.log(TIMEOUT_UNIT_G)/ieee.math_real.log(10.0))), 8);
392	         --
393	         s_initSeqN                  <= toSlv(INIT_SEQ_N_G, 8);
394	      else
395	         -- Use axil register requests
396	         s_closeRq <= s_closeRqReg or s_intCloseRq;
397	         s_openRq  <= s_openRqReg;
398	
399	         -- Assign application side Rssi parameters from Axilite registers
400	         s_appRssiParam <= s_appRssiParamReg;
401	         --
402	         s_initSeqN     <= s_initSeqNReg;
403	      end if;
404	   end process combParamAssign;
