545	         closeRq_o       => s_intCloseRq,
546	         statusReg_o     => s_statusReg,
547	         dropCnt_o       => s_dropCntReg,
548	         validCnt_o      => s_validCntReg,
549	         resendCnt_o     => s_resendCntReg,
550	         reconCnt_o      => s_reconCntReg
