572	         rst_i        => rst_i,
573	         synHeadSt_i  => s_synHeadSt,
574	         rstHeadSt_i  => s_rstHeadSt,
575	         dataHeadSt_i => s_dataHeadSt,
576	         nullHeadSt_i => s_nullHeadSt,
577	         ackHeadSt_i  => s_ackHeadSt,
578	         busyHeadSt_i => s_localBusy,
579	
580	         ack_i          => s_txAckF,    -- Connected to ConnectFSM
581	         txSeqN_i       => s_txSeqN,
582	         rxAckN_i       => s_rxLastSeqN,
583	         headerValues_i => s_rssiParam,
584	         addr_i         => s_headerAddr,
585	         headerData_o   => s_headerData,
586	         ready_o        => s_headerRdy,
587	         headerLength_o => s_txChkLength);
588	
589	   -- TX FSM
590	   -----------------------------------------
591	   -- Group all ack requests
592	   s_sndAck <= s_sndAckCon or s_sndAckMon;
593	
594	   --
595	   TxFSM_INST : entity surf.RssiTxFsm
596	      generic map (
597	         TPD_G               => TPD_G,
598	         WINDOW_ADDR_SIZE_G  => WINDOW_ADDR_SIZE_G,
599	         SEGMENT_ADDR_SIZE_G => SEGMENT_ADDR_SIZE_G,
600	         SYN_HEADER_SIZE_G   => SYN_HEADER_SIZE_C,
601	         ACK_HEADER_SIZE_G   => ACK_HEADER_SIZE_C,
602	         EACK_HEADER_SIZE_G  => EACK_HEADER_SIZE_C,
603	         RST_HEADER_SIZE_G   => RST_HEADER_SIZE_C,
604	         NULL_HEADER_SIZE_G  => NULL_HEADER_SIZE_C,
605	         DATA_HEADER_SIZE_G  => DATA_HEADER_SIZE_C,
606	         HEADER_CHKSUM_EN_G  => HEADER_CHKSUM_EN_G)
607	      port map (
608	         clk_i         => clk_i,
609	         rst_i         => rst_i,
610	         connActive_i  => s_connActive,
611	         closed_i      => s_closed,
612	         injectFault_i => s_injectFault,
613	
614	         sndSyn_i    => s_sndSyn,
615	         sndAck_i    => s_sndAck,
616	         sndRst_i    => s_sndRst,
617	         sndResend_i => s_sndResend,
618	         sndNull_i   => s_sndNull,
619	
620	         windowSize_i => s_txWindowSize,
621	         bufferSize_i => s_txBufferSize,
622	
623	
624	         wrBuffWe_o   => s_txWrBuffWe,
625	         wrBuffAddr_o => s_txWrBuffAddr,
626	         wrBuffData_o => s_txWrBuffData,
627	         rdBuffAddr_o => s_txRdBuffAddr,
628	         rdBuffData_i => s_txRdBuffData,
629	
630	         rdHeaderAddr_o => s_headerAddr,
631	         rdHeaderData_i => s_headerData,
632	         headerRdy_i    => s_headerRdy,
633	         headerLength_i => s_txChkLength,
634	
635	         chksumValid_i  => s_txChkValid,
636	         chksumEnable_o => s_txChkEnable,
637	         chksumStrobe_o => s_txChkStrobe,
638	         chksum_i       => s_txChksum,
639	
640	         initSeqN_i => s_initSeqN,
641	
642	         txSeqN_o     => s_txSeqN,
643	         synHeadSt_o  => s_synHeadSt,
644	         ackHeadSt_o  => s_ackHeadSt,
645	         dataHeadSt_o => s_dataHeadSt,
646	         dataSt_o     => open,  -- may be used in the future otherwise remove
647	         rstHeadSt_o  => s_rstHeadSt,
648	         nullHeadSt_o => s_nullHeadSt,
649	
650	         txTspState_o => s_txTspState,
651	         txAppState_o => s_txAppState,
652	         txAckState_o => s_txAckState,
653	
654	         lastAckN_o => s_rxLastAckN,
655	         ack_i      => s_rxAck,
656	         ackN_i     => s_rxAckN,
657	
658	         appSsiMaster_i => s_sAppSsiMaster,
659	         appSsiSlave_o  => s_sAppSsiSlave,
660	
661	         tspSsiSlave_i  => s_mTspSsiSlave,
662	         tspSsiMaster_o => s_mTspSsiMaster,
663	
664	         bufferEmpty_o => s_txBufferEmpty,
665	         lenErr_o      => s_lenErr,
666	         ackErr_o      => s_ackErr);
667	
668	   -----------------------------------------------
669	   -- Tx buffer RAM
670	   GEN_TX : if (BYP_TX_BUFFER_G = false) generate
671	
672	      GEN_XPM : if (SYNTH_MODE_G = "xpm") generate
673	         U_RAM : entity surf.SimpleDualPortRamXpm
674	            generic map (
675	               TPD_G         => TPD_G,
676	               COMMON_CLK_G  => true,
677	               MEMORY_TYPE_G => MEMORY_TYPE_G,
678	               DATA_WIDTH_G  => RSSI_WORD_WIDTH_C*8,
679	               ADDR_WIDTH_G  => BUFFER_ADDR_WIDTH_C)
680	            port map (
681	               -- Port A - Write only
682	               clka   => clk_i,
683	               wea(0) => s_txWrBuffWe,
684	               addra  => s_txWrBuffAddr,
685	               dina   => s_txWrBuffData,
686	               -- Port B - Read only
687	               clkb   => clk_i,
688	               rstb   => rst_i,
689	               addrb  => s_txRdBuffAddr,
690	               doutb  => s_txRdBuffData);
691	      end generate;
692	
693	      GEN_ALTERA : if (SYNTH_MODE_G = "altera_mf") generate
694	         U_RAM : entity surf.SimpleDualPortRamAlteraMf
695	            generic map (
696	               TPD_G         => TPD_G,
697	               COMMON_CLK_G  => true,
698	               MEMORY_TYPE_G => MEMORY_TYPE_G,
699	               DATA_WIDTH_G  => RSSI_WORD_WIDTH_C*8,
700	               ADDR_WIDTH_G  => BUFFER_ADDR_WIDTH_C)
701	            port map (
702	               -- Port A - Write only
703	               clka   => clk_i,
704	               wea(0) => s_txWrBuffWe,
705	               addra  => s_txWrBuffAddr,
706	               dina   => s_txWrBuffData,
707	               -- Port B - Read only
708	               clkb   => clk_i,
709	               rstb   => rst_i,
710	               addrb  => s_txRdBuffAddr,
711	               doutb  => s_txRdBuffData);
712	      end generate;
713	
714	      GEN_INFERRED : if (SYNTH_MODE_G = "inferred") generate
715	         U_RAM : entity surf.SimpleDualPortRam
716	            generic map (
717	               TPD_G        => TPD_G,
718	               DATA_WIDTH_G => RSSI_WORD_WIDTH_C*8,
719	               ADDR_WIDTH_G => BUFFER_ADDR_WIDTH_C)
720	            port map (
721	               -- Port A - Write only
722	               clka  => clk_i,
723	               wea   => s_txWrBuffWe,
724	               addra => s_txWrBuffAddr,
725	               dina  => s_txWrBuffData,
726	               -- Port B - Read only
727	               clkb  => clk_i,
728	               rstb  => rst_i,
729	               addrb => s_txRdBuffAddr,
730	               doutb => s_txRdBuffData);
731	      end generate;
732	
733	   end generate;
734	
735	   tx_Chksum_INST : entity surf.RssiChksum
736	      generic map (
737	         TPD_G        => TPD_G,
738	         DATA_WIDTH_G => 64,
739	         CSUM_WIDTH_G => 16
740	         )
741	      port map (
742	         clk_i    => clk_i,
743	         rst_i    => rst_i,
744	         enable_i => s_txChkEnable,
745	         strobe_i => s_txChkStrobe,
746	         init_i   => x"0000",
747	         length_i => s_txChkLength,
748	         data_i   => endianSwap64(s_mTspSsiMaster.data(RSSI_WORD_WIDTH_C*8-1 downto 0)),
749	         chksum_o => s_txChksum,
750	         valid_o  => s_txChkValid,
751	         check_o  => open);
752	
753	   -- /////////////////////////////////////////////////////////
754	   ------------------------------------------------------------
755	   -- RX part
756	   ------------------------------------------------------------
757	   -- /////////////////////////////////////////////////////////
758	   RxFSM_INST : entity surf.RssiRxFsm
759	      generic map (
760	         TPD_G               => TPD_G,
761	         WINDOW_ADDR_SIZE_G  => WINDOW_ADDR_SIZE_G,
762	         HEADER_CHKSUM_EN_G  => HEADER_CHKSUM_EN_G,
763	         SEGMENT_ADDR_SIZE_G => SEGMENT_ADDR_SIZE_G)
764	      port map (
765	         clk_i          => clk_i,
766	         rst_i          => rst_i,
767	         connActive_i   => s_connActive,
768	         rxWindowSize_i => s_rxWindowSize,
769	         rxBufferSize_i => s_rxBufferSize,
770	         txWindowSize_i => s_txWindowSize,
771	         lastAckN_i     => s_rxLastAckN,  --
772	         rxLastSeqN_o   => s_rxLastSeqN,
773	         rxAckN_o       => s_rxAckN,
774	         rxValidSeg_o   => s_rxValidSeg,
775	         rxDropSeg_o    => s_rxDropSeg,
776	         rxFlags_o      => s_rxFlags,
777	         rxParam_o      => s_rxRssiParam,
778	         rxTspState_o   => s_rxTspState,
779	         rxAppState_o   => s_rxAppState,
780	         chksumValid_i  => s_rxChkValid,
781	         chksumOk_i     => s_rxChkCheck,
782	         chksumEnable_o => s_rxChkEnable,
783	         chksumStrobe_o => s_rxChkStrobe,
784	         chksumLength_o => s_rxChkLength,
785	         wrBuffWe_o     => s_rxWrBuffWe,
786	         wrBuffAddr_o   => s_rxWrBuffAddr,
787	         wrBuffData_o   => s_rxWrBuffData,
788	         rdBuffAddr_o   => s_rxRdBuffAddr,
789	         rdBuffData_i   => s_rxRdBuffData,
790	         tspSsiMaster_i => s_sTspSsiMaster,
791	         tspSsiSlave_o  => s_sTspSsiSlave,
792	         appSsiMaster_o => s_mAppSsiMaster,
793	         appSsiSlave_i  => s_mAppSsiSlave);
794	
795	   -- Rx buffer RAM
796	   GEN_RX : if (BYP_RX_BUFFER_G = false) generate
797	
798	      GEN_XPM : if (SYNTH_MODE_G = "xpm") generate
799	         U_RAM : entity surf.SimpleDualPortRamXpm
800	            generic map (
801	               TPD_G         => TPD_G,
802	               COMMON_CLK_G  => true,
803	               MEMORY_TYPE_G => MEMORY_TYPE_G,
804	               DATA_WIDTH_G  => RSSI_WORD_WIDTH_C*8,
805	               ADDR_WIDTH_G  => BUFFER_ADDR_WIDTH_C)
806	            port map (
807	               -- Port A - Write only
808	               clka   => clk_i,
809	               wea(0) => s_rxWrBuffWe,
810	               addra  => s_rxWrBuffAddr,
811	               dina   => s_rxWrBuffData,
812	               -- Port B - Read only
813	               clkb   => clk_i,
814	               rstb   => rst_i,
815	               addrb  => s_rxRdBuffAddr,
816	               doutb  => s_rxRdBuffData);
817	      end generate;
818	
819	      GEN_ALTERA : if (SYNTH_MODE_G = "altera_mf") generate
820	         U_RAM : entity surf.SimpleDualPortRamAlteraMf
821	            generic map (
822	               TPD_G         => TPD_G,
823	               COMMON_CLK_G  => true,
824	               MEMORY_TYPE_G => MEMORY_TYPE_G,
825	               DATA_WIDTH_G  => RSSI_WORD_WIDTH_C*8,
826	               ADDR_WIDTH_G  => BUFFER_ADDR_WIDTH_C)
827	            port map (
828	               -- Port A - Write only
829	               clka   => clk_i,
830	               wea(0) => s_rxWrBuffWe,
831	               addra  => s_rxWrBuffAddr,
832	               dina   => s_rxWrBuffData,
833	               -- Port B - Read only
834	               clkb   => clk_i,
835	               rstb   => rst_i,
836	               addrb  => s_rxRdBuffAddr,
837	               doutb  => s_rxRdBuffData);
838	      end generate;
839	
840	      GEN_INFERRED : if (SYNTH_MODE_G = "inferred") generate
841	         U_RAM : entity surf.SimpleDualPortRam
842	            generic map (
843	               TPD_G        => TPD_G,
844	               DATA_WIDTH_G => RSSI_WORD_WIDTH_C*8,
845	               ADDR_WIDTH_G => BUFFER_ADDR_WIDTH_C)
846	            port map (
847	               -- Port A - Write only
848	               clka  => clk_i,
849	               wea   => s_rxWrBuffWe,
850	               addra => s_rxWrBuffAddr,
851	               dina  => s_rxWrBuffData,
852	               -- Port B - Read only
853	               clkb  => clk_i,
854	               rstb  => rst_i,
855	               addrb => s_rxRdBuffAddr,
856	               doutb => s_rxRdBuffData);
857	      end generate;
858	
859	   end generate;
860	
861	   -- Acknowledge valid packet
862	   s_rxAck <= s_rxValidSeg and s_rxFlags.ack and s_connActive;
863	
864	   rx_Chksum_INST : entity surf.RssiChksum
865	      generic map (
866	         TPD_G        => TPD_G,
867	         DATA_WIDTH_G => 64,
868	         CSUM_WIDTH_G => 16
869	         )
870	      port map (
871	         clk_i    => clk_i,
872	         rst_i    => rst_i,
873	         enable_i => s_rxChkEnable,
874	         strobe_i => s_rxChkStrobe,
875	         init_i   => x"0000",
876	         length_i => s_rxChkLength,
877	         data_i   => s_rxWrBuffData,
878	         chksum_o => open,
879	         valid_o  => s_rxChkValid,
880	         check_o  => s_rxChkCheck);
881	
882	   -- /////////////////////////////////////////////////////////
883	   ------------------------------------------------------------
884	   -- Output SSI conversion to AXIS
885	   ------------------------------------------------------------
886	   -- /////////////////////////////////////////////////////////
887	
888	   -- SSI Application side
889	   s_mAppAxisMaster <= ssi2AxisMaster(RSSI_AXIS_CONFIG_C, s_mAppSsiMaster);
890	   s_mAppSsiSlave   <= axis2SsiSlave(RSSI_AXIS_CONFIG_C, s_mAppAxisSlave, s_mAppAxisCtrl);
891	   s_localBusy      <= s_mAppfifoWrCnt(SEGMENT_ADDR_SIZE_G);
892	
893	   -- SSI Transport side
894	   s_mTspAxisMaster <= ssi2AxisMaster(RSSI_AXIS_CONFIG_C, s_mTspSsiMaster);
895	   s_mTspSsiSlave   <= axis2SsiSlave(RSSI_AXIS_CONFIG_C, s_mTspAxisSlave, s_mTspAxisCtrl);
896	
897	   -- /////////////////////////////////////////////////////////
898	   ------------------------------------------------------------
899	   -- Output AXIS fifos
900	   ------------------------------------------------------------
901	   -- /////////////////////////////////////////////////////////
902	
903	   -- Application side
904	   AppFifoOut_INST : entity surf.AxiStreamFifoV2
905	      generic map (
906	         TPD_G               => TPD_G,
907	         SLAVE_READY_EN_G    => false,  -- Using pause
908	         GEN_SYNC_FIFO_G     => true,
909	         SYNTH_MODE_G        => SYNTH_MODE_G,
910	         MEMORY_TYPE_G       => "block",
911	         FIFO_ADDR_WIDTH_G   => SEGMENT_ADDR_SIZE_G+1,  -- Enough to store 2 segments
912	         FIFO_FIXED_THRESH_G => true,
913	         FIFO_PAUSE_THRESH_G => (2**SEGMENT_ADDR_SIZE_G) - 16,  -- Threshold at 1 segment minus padding
914	         INT_WIDTH_SELECT_G  => "CUSTOM",
915	         INT_DATA_WIDTH_G    => RSSI_WORD_WIDTH_C,
916	         SLAVE_AXI_CONFIG_G  => RSSI_AXIS_CONFIG_C,
917	         MASTER_AXI_CONFIG_G => APP_AXIS_CONFIG_G)
918	      port map (
919	         sAxisClk    => clk_i,
920	         sAxisRst    => s_rstFifo,
921	         sAxisMaster => s_mAppAxisMaster,
922	         sAxisSlave  => s_mAppAxisSlave,
923	         sAxisCtrl   => s_mAppAxisCtrl,
924	         fifoWrCnt   => s_mAppfifoWrCnt,
925	         --
926	         mAxisClk    => clk_i,
927	         mAxisRst    => s_rstFifo,
928	         mAxisMaster => monMasters(1),
929	         mAxisSlave  => monSlaves(1),
930	         mTLastTUser => open);
931	
932	   mAppAxisMaster_o <= monMasters(1);
933	   monSlaves(1)     <= mAppAxisSlave_i;
934	
935	   -- Transport side
936	   TspFifoOut_INST : entity surf.AxiStreamFifoV2
937	      generic map (
938	         TPD_G               => TPD_G,
939	         SLAVE_READY_EN_G    => false,  -- Using pause
940	         GEN_SYNC_FIFO_G     => true,
941	         SYNTH_MODE_G        => SYNTH_MODE_G,
942	         MEMORY_TYPE_G       => "block",
943	         FIFO_ADDR_WIDTH_G   => SEGMENT_ADDR_SIZE_G+1,  -- Enough to store 2 segments
944	         FIFO_FIXED_THRESH_G => true,
945	         FIFO_PAUSE_THRESH_G => (2**SEGMENT_ADDR_SIZE_G) - 16,  -- Threshold at 1 segment minus padding
946	         INT_WIDTH_SELECT_G  => "CUSTOM",
947	         INT_DATA_WIDTH_G    => RSSI_WORD_WIDTH_C,
948	         SLAVE_AXI_CONFIG_G  => RSSI_AXIS_CONFIG_C,
949	         MASTER_AXI_CONFIG_G => TSP_AXIS_CONFIG_G)
950	      port map (
951	         sAxisClk    => clk_i,
952	         sAxisRst    => rst_i,
953	         sAxisMaster => s_mTspAxisMaster,
954	         sAxisSlave  => s_mTspAxisSlave,
955	         sAxisCtrl   => s_mTspAxisCtrl,
956	         --
957	         mAxisClk    => clk_i,
958	         mAxisRst    => rst_i,
959	         mAxisMaster => mTspAxisMaster_o,
960	         mAxisSlave  => mTspAxisSlave_i,
961	         mTLastTUser => open);
962	----------------------------------------
963	-- Output assignment
964	   statusReg_o <= s_statusReg;
965	
966	   PACKET_RATE :
967	   for i in 1 downto 0 generate
968	      U_AxiStreamMon : entity surf.AxiStreamMon
969	         generic map (
970	            TPD_G           => TPD_G,
971	            AXIS_CLK_FREQ_G => CLK_FREQUENCY_G,
972	            AXIS_CONFIG_G   => APP_AXIS_CONFIG_G)
973	         port map (
974	            -- AXIS Stream Interface
975	            axisClk    => clk_i,
976	            axisRst    => rst_i,
977	            axisMaster => monMasters(i),
978	            axisSlave  => monSlaves(i),
979	            -- Status Interface
980	            statusClk  => axiClk_i,
981	            statusRst  => axiRst_i,
982	            frameRate  => frameRate(i),
983	            bandwidth  => bandwidth(i));
984	   end generate PACKET_RATE;
985	
986	   maxSegSize_o <= s_rxRssiParam.maxSegSize;
987	
988	end architecture rtl;
