33	-- top-level directory of this distribution and at:
34	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
35	-- No part of 'SLAC Firmware Standard Library', including this file,
36	-- may be copied, modified, propagated, or distributed except according to
37	-- the terms contained in the LICENSE.txt file.
38	-------------------------------------------------------------------------------
39	
40	library ieee;
41	use ieee.std_logic_1164.all;
42	use ieee.std_logic_unsigned.all;
43	use ieee.std_logic_arith.all;
44	
45	
46	library surf;
47	use surf.StdRtlPkg.all;
48	use surf.RssiPkg.all;
49	use surf.SsiPkg.all;
50	use surf.AxiStreamPkg.all;
51	
52	entity RssiTxFsm is
53	   generic (
54	      TPD_G : time := 1 ns;
55	
56	      WINDOW_ADDR_SIZE_G  : positive := 3;  -- 2^WINDOW_ADDR_SIZE_G  = Number of segments
57	      SEGMENT_ADDR_SIZE_G : positive := 7;  -- 2^SEGMENT_ADDR_SIZE_G = Number of 64 bit wide data words
58	
59	      SYN_HEADER_SIZE_G  : natural := 24;
60	      ACK_HEADER_SIZE_G  : natural := 8;
61	      EACK_HEADER_SIZE_G : natural := 8;
62	      RST_HEADER_SIZE_G  : natural := 8;
63	      NULL_HEADER_SIZE_G : natural := 8;
64	      DATA_HEADER_SIZE_G : natural := 8;
65	
66	      HEADER_CHKSUM_EN_G : boolean := true
67	      );
68	   port (
69	      clk_i : in sl;
70	      rst_i : in sl;
71	
72	      -- Connection FSM indicating active connection
73	      connActive_i : in sl;
74	      -- Closed state in connFSM (initialize seqN)
75	      closed_i     : in sl;
76	
77	      -- Fault injection corrupts header checksum
78	      injectFault_i : in sl;
79	
80	      -- Various segment requests
81	      sndSyn_i    : in sl;
82	      sndAck_i    : in sl;
83	      sndRst_i    : in sl;
84	      sndResend_i : in sl;
85	      sndNull_i   : in sl;
86	
87	      -- Window buff size (Depends on the number of outstanding segments)
88	      windowSize_i : in integer range 1 to 2 ** (WINDOW_ADDR_SIZE_G);
89	      bufferSize_i : in integer range 1 to 2 ** (SEGMENT_ADDR_SIZE_G);
90	
91	      -- Buffer write
92	      wrBuffWe_o   : out sl;
93	      wrBuffAddr_o : out slv((SEGMENT_ADDR_SIZE_G+WINDOW_ADDR_SIZE_G)-1 downto 0);
94	      wrBuffData_o : out slv(RSSI_WORD_WIDTH_C*8-1 downto 0);
95	
96	      -- Buffer read
97	      rdBuffAddr_o : out slv((SEGMENT_ADDR_SIZE_G+WINDOW_ADDR_SIZE_G)-1 downto 0);
98	      rdBuffData_i : in  slv(RSSI_WORD_WIDTH_C*8-1 downto 0);
99	
100	      -- Header read
101	      rdHeaderAddr_o : out slv(7 downto 0);
102	      rdHeaderData_i : in  slv(RSSI_WORD_WIDTH_C*8-1 downto 0);
103	      --
104	      headerRdy_i    : in  sl;
105	      headerLength_i : in  positive;  -- Unconnected for now will be used when EACK
106	
107	      -- Checksum control
108	      chksumValid_i  : in  sl;
109	      chksumEnable_o : out sl;
110	      chksumStrobe_o : out sl;
111	      --
112	      chksum_i       : in  slv(15 downto 0);
113	
114	      -- Initial sequence number
115	      initSeqN_i : in slv(7 downto 0);
116	
117	      -- Tx data (input to header decoder module)
118	      txSeqN_o : out slv(7 downto 0);
119	
120	      -- FSM outs for header and data flow control
121	      synHeadSt_o  : out sl;
122	      ackHeadSt_o  : out sl;
123	      dataHeadSt_o : out sl;
124	      dataSt_o     : out sl;
125	      rstHeadSt_o  : out sl;
126	      nullHeadSt_o : out sl;
127	
128	      -- Debug
129	      txTspState_o : out slv(7 downto 0);
130	      txAppState_o : out slv(3 downto 0);
131	      txAckState_o : out slv(3 downto 0);
132	
133	      -- Last acked number (Used in Rx FSM to determine if AcnN is valid)
134	      lastAckN_o : out slv(7 downto 0);
135	
136	      -- Acknowledge mechanism
137	      ack_i  : in sl;  -- From receiver module when a segment with valid ACK is received
138	      ackN_i : in slv(7 downto 0);      -- Number being ACKed
139	      --eack_i        : in sl;                 -- From receiver module when a segment with valid EACK is received
140	      --eackSeqnArr_i : in Slv8Array(0 to MAX_RX_NUM_OUTS_SEG_G-1); -- Array of sequence numbers received out of order
141	
142	      -- SSI Application side interface IN
143	      appSsiMaster_i : in  SsiMasterType;
144	      appSsiSlave_o  : out SsiSlaveType;
145	
146	      -- SSI Transport side interface OUT
147	      tspSsiSlave_i  : in  SsiSlaveType;
148	      tspSsiMaster_o : out SsiMasterType;
149	
150	      -- Errors (1 cc pulse)
151	      lenErr_o : out sl;
152	      ackErr_o : out sl;
153	
154	      -- Segment buffer indicator
155	      bufferEmpty_o : out sl
156	      );
157	end entity RssiTxFsm;
158	
159	architecture rtl of RssiTxFsm is
160	
161	   -- Init SSI bus
162	   constant SSI_MASTER_INIT_C  : SsiMasterType := axis2SsiMaster(RSSI_AXIS_CONFIG_C, AXI_STREAM_MASTER_INIT_C);
163	   constant SSI_SLAVE_NOTRDY_C : SsiSlaveType  := axis2SsiSlave(RSSI_AXIS_CONFIG_C, AXI_STREAM_SLAVE_INIT_C, AXI_STREAM_CTRL_INIT_C);
164	   constant SSI_SLAVE_RDY_C    : SsiSlaveType  := axis2SsiSlave(RSSI_AXIS_CONFIG_C, AXI_STREAM_SLAVE_FORCE_C, AXI_STREAM_CTRL_INIT_C);
165	
166	   type TspStateType is (
167	      --
168	      INIT_S,
169	      DISS_CONN_S,
170	      CONN_S,
171	      --
172	      SYN_H_S,
173	      ACK_H_S,
174	      RST_H_S,
175	      NULL_H_S,
176	      DATA_H_S,
177	      DATA_S,
178	      DATA_SENT_S,
179	      --
180	      RST_WE_S,
181	      DATA_WE_S,
182	      NULL_WE_S,
183	      --
184	      RESEND_INIT_S,
185	      RESEND_H_S,
186	      RESEND_DATA_S,
187	      RESEND_PP_S
188	      );
189	
190	   type AppStateType is (
191	      IDLE_S,
192	      WAIT_SOF_S,
193	      SEG_RCV_S,
194	      SEG_RDY_S,
195	      SEG_LEN_ERR
196	      );
197	
198	   type AckStateType is (
199	      IDLE_S,
200	      ERR_S,
201	      ACK_S
202	    --EACK_S,
203	      );
204	
205	   type RegType is record
206	
207	      -- Buffer window handling and acknowledgment control
208	      -----------------------------------------
209	      windowArray    : WindowTypeArray(0 to 2 ** WINDOW_ADDR_SIZE_G-1);
210	      firstUnackAddr : slv(WINDOW_ADDR_SIZE_G-1 downto 0);
211	      nextSentAddr   : slv(WINDOW_ADDR_SIZE_G-1 downto 0);
212	      lastSentAddr   : slv(WINDOW_ADDR_SIZE_G-1 downto 0);
213	
214	      lastAckSeqN : slv(7 downto 0);
215	      --eackAddr       : slv(WINDOW_ADDR_SIZE_G-1 downto 0);
216	      --eackIndex      : integer;
217	      bufferFull  : sl;
218	      bufferEmpty : sl;
219	      ackErr      : sl;
220	
221	      -- State Machine
222	      ackState   : AckStateType;
223	      txAckState : slv(3 downto 0);
224	
225	      -- Application side FSM
226	      -----------------------------------------
227	      rxSegmentAddr : slv(SEGMENT_ADDR_SIZE_G downto 0);  -- One address bit more to check the overflow
228	      rxBufferAddr  : slv(WINDOW_ADDR_SIZE_G-1 downto 0);
229	      rxSegmentWe   : sl;
230	      sndData       : sl;
231	      lenErr        : sl;
232	      appBusy       : sl;
233	      appDrop       : sl;
234	
235	      appSsiMaster : SsiMasterType;
236	      appSsiSlave  : SsiSlaveType;
237	
238	      appState   : AppStateType;
239	      txAppState : slv(3 downto 0);
240	
241	      -- Transport side FSM
242	      -----------------------------------------
243	
244	      -- Counters
245	      nextSeqN      : slv(7 downto 0);
246	      seqN          : slv(7 downto 0);
247	      txHeaderAddr  : slv(7 downto 0);
248	      txSegmentAddr : slv(SEGMENT_ADDR_SIZE_G downto 0);
249	      txBufferAddr  : slv(WINDOW_ADDR_SIZE_G-1 downto 0);
250	
251	      -- Data mux flags
252	      synH   : sl;
253	      ackH   : sl;
254	      rstH   : sl;
255	      nullH  : sl;
256	      dataH  : sl;
257	      dataD  : sl;
258	      resend : sl;
259	
260	      ackSndData : sl;
261	
262	      -- Various controls
263	      txRdy    : sl;
264	      buffWe   : sl;
265	      buffSent : sl;
266	      chkEn    : sl;
267	      chkStb   : sl;
268	
269	      -- Fault injection
270	      injectFaultD1  : sl;
271	      injectFaultReg : sl;
272	
273	      -- SSI master
274	      tspSsiMaster : SsiMasterType;
275	      tspSsiSlave  : SsiSlaveType;
276	
277	      -- State Machine
278	      tspState   : tspStateType;
279	      txTspState : slv(7 downto 0);
280	   end record RegType;
281	
282	   constant REG_INIT_C : RegType := (
283	
284	      -- Buffer window handling and acknowledgment control
285	      -----------------------------------------
286	      -- Window control
287	      firstUnackAddr => (others => '0'),
288	      lastSentAddr   => (others => '0'),
289	      nextSentAddr   => (others => '0'),
290	
291	      lastAckSeqN => (others => '0'),
292	      --eackAddr       => (others => '0'),
293	      --eackIndex      => 0,
294	      bufferFull  => '0',
295	      bufferEmpty => '1',
296	      windowArray => (0 to 2 ** WINDOW_ADDR_SIZE_G-1 => WINDOW_INIT_C),
297	      ackErr      => '0',
298	
299	      ackState   => IDLE_S,
300	      txAckState => (others => '0'),
301	
302	      -- Application side FSM
303	      -----------------------------------------
304	      rxSegmentAddr => (others => '0'),
305	      rxSegmentWe   => '0',
306	      rxBufferAddr  => (others => '0'),
307	      sndData       => '0',
308	      lenErr        => '0',
309	      appBusy       => '0',
310	      appDrop       => '0',
311	
312	      appSsiMaster => SSI_MASTER_INIT_C,
313	      appSsiSlave  => SSI_SLAVE_NOTRDY_C,
314	
315	      appState   => IDLE_S,
316	      txAppState => (others => '0'),
317	
318	      -- Transport side FSM
319	      -----------------------------------------
320	      nextSeqN      => (others => '0'),
321	      seqN          => (others => '0'),
322	      txHeaderAddr  => (others => '0'),
323	      txSegmentAddr => (others => '0'),
324	      txBufferAddr  => (others => '0'),
325	
326	      --
327	      synH   => '0',
328	      ackH   => '0',
329	      rstH   => '0',
330	      nullH  => '0',
331	      dataH  => '0',
332	      dataD  => '0',
333	      resend => '0',
334	
335	      ackSndData => '0',
336	
337	      --
338	      txRdy    => '0',
339	      buffWe   => '0',
340	      buffSent => '0',
341	      chkEn    => '0',
342	      chkStb   => '0',
343	
344	      -- Fault injection
345	      injectFaultD1  => '0',
346	      injectFaultReg => '0',
347	
348	      -- SSI master
349	      tspSsiMaster => SSI_MASTER_INIT_C,
350	      tspSsiSlave  => SSI_SLAVE_NOTRDY_C,
