356	
357	   signal r                 : RegType := REG_INIT_C;
358	   signal rin               : RegType;
359	   signal s_chksum          : slv(chksum_i'range);
360	   signal s_headerAndChksum : slv(RSSI_WORD_WIDTH_C*8-1 downto 0);
361	
362	   -- attribute dont_touch                      : string;
363	   -- attribute dont_touch of r                 : signal is "TRUE";
364	   -- attribute dont_touch of s_chksum          : signal is "TRUE";
365	   -- attribute dont_touch of s_headerAndChksum : signal is "TRUE";
366	
367	begin
368	
369	   -- Send all 0 if checksum disabled
370	   s_chksum          <= ite(HEADER_CHKSUM_EN_G, chksum_i, (chksum_i'range => '0'));
371	   s_headerAndChksum <= rdHeaderData_i(63 downto 16) & s_chksum(15 downto 0);
372	
373	   -----------------------------------------------------------------------------------------------
374	   comb : process (ackN_i, ack_i, appSsiMaster_i, bufferSize_i, chksumValid_i,
375	                   closed_i, connActive_i, headerLength_i, headerRdy_i,
376	                   initSeqN_i, injectFault_i, r, rdBuffData_i, rdHeaderData_i,
377	                   rst_i, s_headerAndChksum, sndAck_i, sndNull_i, sndResend_i,
378	                   sndRst_i, sndSyn_i, tspSsiSlave_i, windowSize_i) is
379	
380	      variable v : RegType;
381	
382	   begin
383	      v := r;
384	
385	
386	      v.ackSndData := '0';
387	      v.appDrop    := '0';
388	
389	      -- /////////////////////////////////////////////////////////
390	      ------------------------------------------------------------
391	      -- Buffer window handling
392	      ------------------------------------------------------------
393	      -- /////////////////////////////////////////////////////////
394	
395	      ------------------------------------------------------------
396	      -- Buffer full if next slot is occupied
397	      if (r.windowArray(conv_integer(v.rxBufferAddr)).occupied = '1') then
398	         v.bufferFull := '1';
399	      else
400	         v.bufferFull := '0';
401	      end if;
402	
403	      ------------------------------------------------------------
404	      -- Buffer empty if next unacknowledged slot is unoccupied
405	      if (r.windowArray(conv_integer(r.firstUnackAddr)).occupied = '0') then
406	         v.bufferEmpty := '1';
407	      else
408	         v.bufferEmpty := '0';
409	      end if;
410	
411	      ------------------------------------------------------------
412	      -- Write seqN and segment type to window array
413	      ------------------------------------------------------------
414	      if (r.buffWe = '1') then
415	         v.windowArray(conv_integer(r.nextSentAddr)).seqN     := r.nextSeqN;
416	         v.windowArray(conv_integer(r.nextSentAddr)).segType  := r.rstH & r.nullH & r.dataH;
417	         v.windowArray(conv_integer(r.nextSentAddr)).occupied := '1';
418	
419	         -- Update last sent address when new segment is being sent
420	         v.lastSentAddr := r.nextSentAddr;
421	      else
422	         v.windowArray := r.windowArray;
423	      end if;
424	
425	      ------------------------------------------------------------
426	      -- When buffer is sent increase nextSentAddr
427	      ------------------------------------------------------------
428	      if (r.buffSent = '1') then
429	
430	         if r.nextSentAddr < (windowSize_i-1) then
431	            v.nextSentAddr := r.nextSentAddr +1;
432	         else
433	            v.nextSentAddr := (others => '0');
434	         end if;
435	
436	      else
437	         v.nextSentAddr := r.nextSentAddr;
438	      end if;
439	
440	      -- /////////////////////////////////////////////////////////
441	      ------------------------------------------------------------
442	      -- ACK FSM
443	      -- Acknowledgment mechanism to increment firstUnackAddr
444	      -- Place out of order flags from EACK table (Not in Version 1)
445	      ------------------------------------------------------------
446	      -- /////////////////////////////////////////////////////////
447	
448	      case r.ackState is
449	         ----------------------------------------------------------------------
450	         when IDLE_S =>
451	            v.txAckState := x"0";
452	
453	            -- Hold ACK address
454	            v.firstUnackAddr := r.firstUnackAddr;
455	            v.lastAckSeqN    := r.lastAckSeqN;
456	            --v.eackAddr       := r.firstUnackAddr;
457	            --v.eackIndex      := 0;
458	            v.ackErr         := '0';
459	
460	            -- Next state condition
461	            if (ack_i = '1') then
462	               v.ackState := ACK_S;
463	            end if;
464	         ----------------------------------------------------------------------
465	         when ACK_S =>
466	            v.txAckState := x"1";
467	
468	            -- If the same ackN received do nothing
469	            if (r.lastAckSeqN = ackN_i) then
470	               v.firstUnackAddr := r.firstUnackAddr;
471	            -- Increment ACK address until seqN is found next received
472	            elsif r.firstUnackAddr < (windowSize_i-1) then
473	               v.windowArray(conv_integer(r.firstUnackAddr)).occupied := '0';
474	               v.firstUnackAddr                                       := r.firstUnackAddr+1;
475	            else
476	               v.windowArray(conv_integer(r.firstUnackAddr)).occupied := '0';
477	               v.firstUnackAddr                                       := (others => '0');
478	            end if;
479	
480	            --v.eackAddr       := r.firstUnackAddr;
481	            -- v.eackIndex      := 0;
482	            v.ackErr := '0';
483	
484	            -- Next state condition
485	
486	            -- If the same ackN received
487	            if (r.lastAckSeqN = ackN_i) then
488	
489	               -- Go back to IDLE
490	               v.ackState := IDLE_S;
491	
492	            elsif (r.firstUnackAddr = r.lastSentAddr and r.windowArray(conv_integer(r.firstUnackAddr)).seqN /= ackN_i) then
493	               -- If the acked seqN is not found go to error state
494	               v.ackState := ERR_S;
495	            elsif (r.windowArray(conv_integer(r.firstUnackAddr)).seqN = ackN_i) then
496	               v.lastAckSeqN := ackN_i;  -- Save the last Acked seqN
497	               --if eack_i = '1' then
498	               -- Go back to init when the acked seqN is found
499	               --   v.ackState   := EACK_S;
500	               --else
501	               -- Go back to init when the acked seqN is found
502	               v.ackState    := IDLE_S;
503	            --end if;
504	            end if;
505	            ----------------------------------------------------------------------
506	            -- when EACK_S =>
507	            -- v.txAckState := x"2";
508	
509	            -- -- Increment EACK address from firstUnackAddr to nextSentAddr
510	            -- if r.eackAddr < (windowSize_i-1) then
511	            -- v.eackAddr  := r.eackAddr+1;
512	            -- else
513	            -- v.eackAddr  := (others => '0');
514	            -- end if;
515	
516	            -- -- For every address check if the sequence number equals value from eackSeqnArr_i array.
517	            -- -- If it matches mark the eack field at the address and compare the next value from the table.
518	            -- if  r.windowArray(conv_integer(r.eackAddr)).seqN = eackSeqnArr_i(r.eackIndex)  then
519	            -- v.windowArray(conv_integer(r.eackAddr)).eacked := '1';
520	            -- v.eackIndex := r.eackIndex + 1;
521	            -- end if;
522	
523	            -- v.firstUnackAddr  := r.firstUnackAddr;
524	            -- v.ackErr          := '0';
525	
526	         -- -- Next state condition
527	         -- if (r.eackAddr = r.nextSentAddr) then
528	         -- -- If the acked seqN is not found go to error state
529	         -- v.appState   := IDLE_S;
530	         -- end if;
531	         ----------------------------------------------------------------------
532	         when ERR_S =>
533	            v.txAckState := x"3";
534	
535	            -- Outputs
536	            v.firstUnackAddr := r.firstUnackAddr;
537	            --v.eackAddr       := r.firstUnackAddr;
538	            --v.eackIndex      := 0;
539	            v.ackErr         := '1';
540	
541	            -- Next state condition
542	            v.ackState := IDLE_S;
543	         ----------------------------------------------------------------------
544	         when others =>
545	            v.txAckState := x"4";
546	
547	            -- Outputs
548	            v.firstUnackAddr := r.firstUnackAddr;
549	            -- v.eackAddr       := r.firstUnackAddr;
550	            -- v.eackIndex      := 0;
551	            v.ackErr         := '1';
552	
553	            -- Next state condition
554	            v.ackState := IDLE_S;
555	      ----------------------------------------------------------------------
556	      end case;
557	
558	      -- /////////////////////////////////////////////////////////
559	      ------------------------------------------------------------
560	      -- Application side FSM
561	      ------------------------------------------------------------
562	      -- /////////////////////////////////////////////////////////
563	
564	      -- Pipeline Master (DFF)
565	      v.appSsiMaster := appSsiMaster_i;
566	      ------------------------------------------------------------
567	      case r.appState is
568	         ----------------------------------------------------------------------
569	         when IDLE_S =>
570	            v.txAppState := x"0";
571	
572	            -- Not ready for application data
573	            v.appSsiSlave := SSI_SLAVE_NOTRDY_C;
574	
575	            -- Buffer write ctl
576	            v.rxSegmentAddr := (others => '0');
577	            v.rxSegmentWe   := '0';
578	            v.rxBufferAddr  := r.rxBufferAddr;
579	
580	            -- txFSM
581	            v.sndData := '0';
582	            v.lenErr  := '0';
583	            v.appBusy := '1';
584	
585	            -- Wait if buffer full
586	            if (v.bufferFull = '0') then
587	               v.appState := WAIT_SOF_S;
588	            end if;
589	         ----------------------------------------------------------------------
590	         when WAIT_SOF_S =>
591	            v.txAppState := x"1";
592	
593	            -- Not ready for application data
594	            v.appSsiSlave := SSI_SLAVE_NOTRDY_C;
595	
596	            -- Buffer write ctl
597	            v.rxSegmentAddr := (others => '0');
598	            v.rxSegmentWe   := '0';
599	            v.rxBufferAddr  := r.rxBufferAddr;
600	
601	            -- txFSM
602	            v.sndData := '0';
603	            v.lenErr  := '0';
604	            v.appBusy := '0';
605	
606	            -- If other segment (NULL, or RST) is requested return to IDLE_S to
607	            -- check if buffer is still available (not full)
608	            if (r.buffWe = '1') then
609	               v.appState := IDLE_S;
610	
611	               -- Increment the buffer window address because a NULL segment has filled the current spot
612	               if r.rxBufferAddr < (windowSize_i-1) then
613	                  v.rxBufferAddr := r.rxBufferAddr+1;
614	               else
615	                  v.rxBufferAddr := (others => '0');
616	               end if;
617	
618	            -- Check for application data
619	            elsif appSsiMaster_i.valid = '1' then
620	
621	               -- SSI Ready to receive data from APP
622	               v.appSsiSlave := SSI_SLAVE_RDY_C;
623	
624	               -- Wait until receiving the first data
625	               -- SOF and EOF received
626	               -- Packet is only one word long go directly to ready!
627	               if (appSsiMaster_i.sof = '1' and appSsiMaster_i.eof = '1') then
628	
629	                  -- First data already received at this point
630	                  v.rxSegmentAddr := r.rxSegmentAddr;
631	                  v.appBusy       := '1';
632	                  v.rxSegmentWe   := '1';
633	
634	                  -- Save packet tKeep of last data word
635	                  v.windowArray(conv_integer(r.rxBufferAddr)).keep    := appSsiMaster_i.keep(RSSI_WORD_WIDTH_C-1 downto 0);
636	                  v.windowArray(conv_integer(r.rxBufferAddr)).segSize := conv_integer(r.rxSegmentAddr(SEGMENT_ADDR_SIZE_G-1 downto 0));
637	
638	                  v.appState := SEG_RDY_S;
639	
640	               -- SOF received
641	               elsif (appSsiMaster_i.sof = '1') then
642	
643	                  -- First data received
644	                  v.rxSegmentAddr := r.rxSegmentAddr;
645	                  v.appBusy       := '1';
646	                  v.rxSegmentWe   := '1';
647	
648	                  v.appState := SEG_RCV_S;
649	
650	               -- Blowing off the data
651	               else
652	                  v.appDrop := '1';  -- Used in simulation and chipscope debugging
653	               end if;
654	            end if;
655	         ----------------------------------------------------------------------
656	         when SEG_RCV_S =>
657	            v.txAppState := x"2";
658	
659	            -- SSI
660	            v.appSsiSlave  := SSI_SLAVE_RDY_C;
661	            v.rxBufferAddr := r.rxBufferAddr;
662	
663	            -- Buffer write if data valid
664	            if (appSsiMaster_i.valid = '1') then
665	               v.rxSegmentAddr := r.rxSegmentAddr + 1;
666	               v.rxSegmentWe   := '1';
667	            else
668	               v.rxSegmentAddr := r.rxSegmentAddr;
669	               v.rxSegmentWe   := '0';
670	            end if;
671	
672	            -- txFSM
673	            v.sndData := '0';
674	            v.lenErr  := '0';
675	            v.appBusy := '1';
676	
677	            -- Wait until receiving EOF
678	            if (appSsiMaster_i.eof = '1' and appSsiMaster_i.valid = '1') then
679	
680	               -- Save packet tKeep of last data word
681	               v.windowArray(conv_integer(r.rxBufferAddr)).keep := appSsiMaster_i.keep(RSSI_WORD_WIDTH_C-1 downto 0);
682	
683	               -- Save packet length (+1 because it has not incremented for EOF yet)
684	               v.windowArray(conv_integer(r.rxBufferAddr)).segSize := conv_integer(r.rxSegmentAddr(SEGMENT_ADDR_SIZE_G-1 downto 0))+1;
685	
686	               v.appState := SEG_RDY_S;
687	            --
688	            elsif (r.rxSegmentAddr > bufferSize_i) then
689	               v.rxSegmentWe := '0';
690	               v.appState    := SEG_LEN_ERR;
691	            elsif (r.rxSegmentAddr(SEGMENT_ADDR_SIZE_G) = '1') then
692	               v.rxSegmentWe := '0';
693	               v.appState    := SEG_LEN_ERR;
694	            end if;
695	         ----------------------------------------------------------------------
696	         when SEG_RDY_S =>
697	            v.txAppState := x"3";
698	
699	            -- SSI
700	            v.appSsiSlave := SSI_SLAVE_NOTRDY_C;
701	
702	            v.rxSegmentAddr := (others => '0');
703	            v.rxSegmentWe   := '0';
704	
705	            -- Request data at txFSM
706	            v.sndData := '1';
707	            v.lenErr  := '0';
708	            v.appBusy := '1';
709	
710	            -- Hold request until accepted
711	            -- And not in resend process
712	            if (r.ackSndData = '1' and v.resend = '0') then
713	               -- Increment the rxBuffer
714	               if r.rxBufferAddr < (windowSize_i-1) then
715	                  v.rxBufferAddr := r.rxBufferAddr+1;
716	               else
717	                  v.rxBufferAddr := (others => '0');
718	               end if;
719	
720	               v.appState := IDLE_S;
721	            end if;
722	         ----------------------------------------------------------------------
723	         when SEG_LEN_ERR =>
724	            v.txAppState := x"4";
725	
726	            -- SSI
727	            v.appSsiSlave          := SSI_SLAVE_NOTRDY_C;
728	            -- Overflow happened (packet too big)
729	            v.appSsiSlave.overflow := '1';
730	
731	            v.rxSegmentAddr := (others => '0');
732	            v.rxSegmentWe   := '0';
733	
734	            -- Request data at txFSM
735	            v.sndData := '0';
736	            v.lenErr  := '1';
737	            v.appBusy := '1';
738	
739	            -- Go back to idle
740	            v.appState := IDLE_S;
741	         ----------------------------------------------------------------------
742	         when others =>
743	            -- Outs
744	            v := REG_INIT_C;
745	
746	            -- Next state condition
747	            v.appState := IDLE_S;
748	      ----------------------------------------------------------------------
749	      end case;
750	
751	
752	      -- /////////////////////////////////////////////////////////
753	      ------------------------------------------------------------
754	      -- Initialization of the parameters when the connection is broken
755	      if (connActive_i = '0') then
756	         v.firstUnackAddr := REG_INIT_C.firstUnackAddr;
757	         v.lastSentAddr   := REG_INIT_C.lastSentAddr;
758	         v.nextSentAddr   := REG_INIT_C.nextSentAddr;
759	         v.rxBufferAddr   := REG_INIT_C.rxBufferAddr;
760	         v.bufferFull     := REG_INIT_C.bufferFull;
761	         v.bufferEmpty    := REG_INIT_C.bufferEmpty;
762	         v.windowArray    := REG_INIT_C.windowArray;
763	
764	         v.lastAckSeqN := initSeqN_i;
765	
766	         v.ackState := REG_INIT_C.ackState;
767	         v.appState := REG_INIT_C.appState;
768	      end if;
769	      ------------------------------------------------------------
770	      -- /////////////////////////////////////////////////////////
771	
772	      -- /////////////////////////////////////////////////////////
773	      ------------------------------------------------------------
774	      -- Arm fault injection on rising edge of injectFault_i
775	      ------------------------------------------------------------
776	      -- /// //////////////////////////////////////////////////////
777	      v.injectFaultD1 := injectFault_i;
778	
779	      if (injectFault_i = '1' and r.injectFaultD1 = '0') then
780	         v.injectFaultReg := '1';
781	      else
782	         v.injectFaultReg := r.injectFaultReg;
783	      end if;
784	
785	
786	      -- /////////////////////////////////////////////////////////
787	      ------------------------------------------------------------
788	      -- Transport side FSM
789	      ------------------------------------------------------------
790	      -- /////////////////////////////////////////////////////////
791	
792	      -- Reset flags
793	      -- These flags will hold if not overridden
794	      v.tspSsiMaster := SSI_MASTER_INIT_C;
795	
796	      -- Pipeline incoming slave
797	      v.tspSsiSlave := tspSsiSlave_i;
798	
799	      case r.tspState is
800	         ----------------------------------------------------------------------
801	         when INIT_S =>
802	            v.txTspState := x"00";
803	
804	            -- Initialize all
805	            v := REG_INIT_C;
806	
807	            -- Register initial sequence number
808	            v.nextSeqN := initSeqN_i;
809	            v.seqN     := r.nextSeqN;
810	
811	            -- Next state condition
812	            if (closed_i = '0') then
813	               v.tspState := DISS_CONN_S;
814	            end if;
815	         ----------------------------------------------------------------------
816	         when DISS_CONN_S =>
817	            v.txTspState := x"01";
818	
819	            -- Counters
820	            v.nextSeqN := r.nextSeqN;
821	            v.seqN     := r.nextSeqN;
822	
823	            v.txHeaderAddr  := (others => '0');
824	            v.txSegmentAddr := (others => '0');
825	
826	            v.txBufferAddr := r.nextSentAddr;
827	            --
828	            v.synH         := '0';
829	            v.ackH         := '0';
830	            v.rstH         := '0';
831	            v.nullH        := '0';
832	            v.dataH        := '0';
833	            v.dataD        := '0';
834	            --
835	            v.txRdy        := '1';
836	            v.buffWe       := '0';
837	            v.buffSent     := '0';
838	            v.chkEn        := '0';
839	            v.chkStb       := '0';
840	
841	            v.tspSsiMaster := SSI_MASTER_INIT_C;
842	
843	            -- Next state condition
844	            if (sndSyn_i = '1') then
845	               v.tspState := SYN_H_S;
846	            elsif (sndAck_i = '1') then
847	               v.tspState := ACK_H_S;
848	            elsif (sndRst_i = '1') then
849	               v.tspState := RST_WE_S;
850	            elsif (connActive_i = '1') then
851	               v.tspState := CONN_S;
852	            elsif (closed_i = '1') then
853	               v.tspState := INIT_S;
854	            end if;
855	         ----------------------------------------------------------------------
856	         when CONN_S =>
857	            v.txTspState := x"02";
858	
859	            -- Counters
860	            v.nextSeqN := r.nextSeqN;
861	            v.seqN     := r.nextSeqN;
862	
863	            v.txHeaderAddr  := (others => '0');
864	            v.txSegmentAddr := (others => '0');
865	
866	            v.txBufferAddr := r.nextSentAddr;
867	            --
868	            v.synH         := '0';
869	            v.ackH         := '0';
870	            v.rstH         := '0';
871	            v.nullH        := '0';
872	            v.dataH        := '0';
873	            v.dataD        := '0';
874	            v.resend       := '0';
875	
876	            --
877	            v.txRdy    := '1';
878	            v.buffWe   := '0';
879	            v.buffSent := '0';
880	            v.chkEn    := '0';
881	            v.chkStb   := '0';
882	
883	            v.tspSsiMaster := SSI_MASTER_INIT_C;
884	
885	            -- Next state condition
886	            if (sndRst_i = '1') then
887	               v.tspState := RST_WE_S;
888	            elsif (r.sndData = '1') and (r.bufferFull = '0') then
