73	library surf;
74	use surf.StdRtlPkg.all;
75	use surf.AxiLitePkg.all;
76	use surf.RssiPkg.all;
77	
78	entity RssiAxiLiteRegItf is
79	   generic (
80	      -- General Configurations
81	      TPD_G                 : time     := 1 ns;
82	      COMMON_CLK_G          : boolean  := false;  -- true if axiClk_i = devClk_i
83	      SEGMENT_ADDR_SIZE_G   : positive := 7;  -- 2^SEGMENT_ADDR_SIZE_G = Number of 64 bit wide data words
84	      -- Defaults form generics
85	      TIMEOUT_UNIT_G        : real     := 1.0E-6;
86	      INIT_SEQ_N_G          : natural  := 16#80#;
87	      CONN_ID_G             : positive := 16#12345678#;
88	      VERSION_G             : positive := 1;
89	      HEADER_CHKSUM_EN_G    : boolean  := true;
90	      MAX_NUM_OUTS_SEG_G    : positive := 8;  --   <=(2**WINDOW_ADDR_SIZE_G)
91	      MAX_SEG_SIZE_G        : positive := 1024;   -- Number of bytes
92	      RETRANS_TOUT_G        : positive := 50;  -- unit depends on TIMEOUT_UNIT_G
93	      ACK_TOUT_G            : positive := 25;  -- unit depends on TIMEOUT_UNIT_G
94	      NULL_TOUT_G           : positive := 200;  -- unit depends on TIMEOUT_UNIT_G
95	      MAX_RETRANS_CNT_G     : positive := 2;
96	      MAX_CUM_ACK_CNT_G     : positive := 3;
97	      MAX_OUT_OF_SEQUENCE_G : natural  := 3);
98	
99	   port (
100	      -- AXI Clk
101	      axiClk_i : in sl;
102	      axiRst_i : in sl;
103	
104	      -- Axi-Lite Register Interface (locClk domain)
105	      axilReadMaster  : in  AxiLiteReadMasterType  := AXI_LITE_READ_MASTER_INIT_C;
106	      axilReadSlave   : out AxiLiteReadSlaveType;
107	      axilWriteMaster : in  AxiLiteWriteMasterType := AXI_LITE_WRITE_MASTER_INIT_C;
108	      axilWriteSlave  : out AxiLiteWriteSlaveType;
109	
110	      -- Rssi Clk
111	      devClk_i : in sl;
112	      devRst_i : in sl;
113	
114	      -- Registers
115	      -- Control (RW)
116	      openRq_o      : out sl;
117	      closeRq_o     : out sl;
118	      mode_o        : out sl;
119	      injectFault_o : out sl;
120	
121	      initSeqN_o     : out slv(7 downto 0);
122	      appRssiParam_o : out RssiParamType;
123	      negRssiParam_i : in  RssiParamType;
124	
125	      -- Status (RO)
126	      txLastAckN_i : in slv(7 downto 0);
127	      rxSeqN_i     : in slv(7 downto 0);
128	      rxAckN_i     : in slv(7 downto 0);
129	      rxLastSeqN_i : in slv(7 downto 0);
130	      txTspState_i : in slv(7 downto 0);
131	      txAppState_i : in slv(3 downto 0);
132	      txAckState_i : in slv(3 downto 0);
133	      rxTspState_i : in slv(3 downto 0);
134	      rxAppState_i : in slv(3 downto 0);
135	      connState_i  : in slv(3 downto 0);
136	      frameRate_i  : in Slv32Array(1 downto 0);
137	      bandwidth_i  : in Slv64Array(1 downto 0);
138	      status_i     : in slv(8 downto 0);
139	      dropCnt_i    : in slv(31 downto 0);
140	      validCnt_i   : in slv(31 downto 0);
141	      resendCnt_i  : in slv(31 downto 0);
142	      reconCnt_i   : in slv(31 downto 0));
143	end RssiAxiLiteRegItf;
144	
145	architecture rtl of RssiAxiLiteRegItf is
146	
147	   type RegType is record
148	      -- Control (RW)
149	      control : slv(4 downto 0);
150	
151	      -- Parameters (RW)
152	      initSeqN     : slv(7 downto 0);
153	      appRssiParam : RssiParamType;
154	
155	      -- AXI lite
156	      axilReadSlave  : AxiLiteReadSlaveType;
157	      axilWriteSlave : AxiLiteWriteSlaveType;
158	   --
159	   end record;
160	
161	   constant REG_INIT_C : RegType := (
162	      -- Control (RW)
163	      control => "01000",
164	
165	      -- Parameters (RW)
166	      initSeqN        => toSlv(INIT_SEQ_N_G, 8),
167	      appRssiParam    => (
168	         version      => toSlv(VERSION_G, 4),
169	         chksumEn     => "1",
170	         timeoutUnit  => toSlv(integer(0.0 - (ieee.math_real.log(TIMEOUT_UNIT_G)/ieee.math_real.log(10.0))), 8),
171	         maxOutsSeg   => toSlv(MAX_NUM_OUTS_SEG_G, 8),
172	         maxSegSize   => toSlv(MAX_SEG_SIZE_G, 16),
173	         retransTout  => toSlv(RETRANS_TOUT_G, 16),
174	         cumulAckTout => toSlv(ACK_TOUT_G, 16),
175	         nullSegTout  => toSlv(NULL_TOUT_G, 16),
176	         maxRetrans   => toSlv(MAX_RETRANS_CNT_G, 8),
177	         maxCumAck    => toSlv(MAX_CUM_ACK_CNT_G, 8),
178	         maxOutofseq  => toSlv(MAX_OUT_OF_SEQUENCE_G, 8),
179	         connectionId => toSlv(CONN_ID_G, 32)),
180	
181	      -- AXI lite
182	      axilReadSlave  => AXI_LITE_READ_SLAVE_INIT_C,
183	      axilWriteSlave => AXI_LITE_WRITE_SLAVE_INIT_C);
184	
185	   signal r   : RegType := REG_INIT_C;
186	   signal rin : RegType;
187	
188	   -- Integer address
189	   signal s_RdAddr : natural := 0;
190	   signal s_WrAddr : natural := 0;
191	
192	   -- Synced status signals
193	   signal s_status    : slv(status_i'range);
194	   signal s_dropCnt   : slv(31 downto 0);
195	   signal s_validCnt  : slv(31 downto 0);
196	   signal s_reconCnt  : slv(31 downto 0);
197	   signal s_resendCnt : slv(31 downto 0);
198	
199	   signal dummyBit     : sl;
200	   signal negRssiParam : RssiParamType;
201	
202	   -- attribute dont_touch                 : string;
203	   -- attribute dont_touch of r            : signal is "TRUE";
204	   -- attribute dont_touch of s_RdAddr     : signal is "TRUE";
205	   -- attribute dont_touch of s_WrAddr     : signal is "TRUE";
206	   -- attribute dont_touch of s_status     : signal is "TRUE";
207	   -- attribute dont_touch of s_dropCnt    : signal is "TRUE";
208	   -- attribute dont_touch of s_reconCnt   : signal is "TRUE";
209	   -- attribute dont_touch of s_resendCnt  : signal is "TRUE";
210	   -- attribute dont_touch of dummyBit     : signal is "TRUE";
211	   -- attribute dont_touch of negRssiParam : signal is "TRUE";
212	
213	begin
214	
215	   -- Convert address to integer (lower two bits of address are always '0')
216	   s_RdAddr <= conv_integer(axilReadMaster.araddr(9 downto 2));
217	   s_WrAddr <= conv_integer(axilWriteMaster.awaddr(9 downto 2));
218	
219	   comb : process (axiRst_i, axilReadMaster, axilWriteMaster, bandwidth_i,
220	                   connState_i, frameRate_i, negRssiParam, r, rxAckN_i,
221	                   rxAppState_i, rxLastSeqN_i, rxSeqN_i, rxTspState_i,
222	                   s_RdAddr, s_WrAddr, s_dropCnt, s_reconCnt, s_resendCnt,
223	                   s_status, s_validCnt, txAckState_i, txAppState_i,
224	                   txLastAckN_i, txTspState_i) is
225	      variable v             : RegType;
226	      variable axilStatus    : AxiLiteStatusType;
227	      variable axilWriteResp : slv(1 downto 0);
228	      variable axilReadResp  : slv(1 downto 0);
229	   begin
230	      -- Latch the current value
231	      v := r;
232	
233	      ----------------------------------------------------------------------------------------------
234	      -- Axi-Lite interface
235	      ----------------------------------------------------------------------------------------------
236	      axiSlaveWaitTxn(axilWriteMaster, axilReadMaster, v.axilWriteSlave, v.axilReadSlave, axilStatus);
237	
238	      if (axilStatus.writeEnable = '1') then
239	         axilWriteResp := ite(axilWriteMaster.awaddr(1 downto 0) = "00", AXI_RESP_OK_C, AXI_RESP_DECERR_C);
240	         case (s_WrAddr) is
241	            when 16#00# =>              -- ADDR (0)
242	               v.control := axilWriteMaster.wdata(4 downto 0);
243	            when 16#01# =>              -- ADDR (4)
244	               v.initSeqN := axilWriteMaster.wdata(7 downto 0);
245	            when 16#02# =>              -- ADDR (8)
246	               v.appRssiParam.version := axilWriteMaster.wdata(3 downto 0);
247	            when 16#03# =>              -- ADDR (12)
248	               v.appRssiParam.maxOutsSeg := axilWriteMaster.wdata(7 downto 0);
249	            when 16#04# =>              -- ADDR (16)
250	               v.appRssiParam.maxSegSize := axilWriteMaster.wdata(15 downto 0);
251	               if (unsigned(v.appRssiParam.maxSegSize) < 8) then
252	                  v.appRssiParam.maxSegSize := toSlv(8, v.appRssiParam.maxSegSize'length);
253	               elsif (unsigned(v.appRssiParam.maxSegSize) > (2**SEGMENT_ADDR_SIZE_G)*8) then
254	                  v.appRssiParam.maxSegSize := toSlv((2**SEGMENT_ADDR_SIZE_G)*8, v.appRssiParam.maxSegSize'length);
255	               end if;
256	            when 16#05# =>
257	               v.appRssiParam.retransTout := axilWriteMaster.wdata(15 downto 0);
258	            when 16#06# =>
259	               v.appRssiParam.cumulAckTout := axilWriteMaster.wdata(15 downto 0);
260	            when 16#07# =>
261	               v.appRssiParam.nullSegTout := axilWriteMaster.wdata(15 downto 0);
262	            when 16#08# =>
263	               v.appRssiParam.maxRetrans := axilWriteMaster.wdata(7 downto 0);
264	            when 16#09# =>
265	               v.appRssiParam.maxCumAck := axilWriteMaster.wdata(7 downto 0);
266	            when 16#0A# =>
267	               v.appRssiParam.maxOutofseq := axilWriteMaster.wdata(7 downto 0);
268	            when 16#0B# =>
269	               v.appRssiParam.connectionId := axilWriteMaster.wdata(31 downto 0);
270	            when others =>
271	               axilWriteResp := AXI_RESP_DECERR_C;
272	         end case;
273	         axiSlaveWriteResponse(v.axilWriteSlave, axilWriteResp);
274	      end if;
275	
276	      if (axilStatus.readEnable = '1') then
277	         axilReadResp := ite(axilReadMaster.araddr(1 downto 0) = "00", AXI_RESP_OK_C, AXI_RESP_DECERR_C);
278	         case (s_RdAddr) is
279	            when 16#00# =>              -- ADDR (0)
280	               v.axilReadSlave.rdata(4 downto 0) := r.control;
281	            when 16#01# =>              -- ADDR (4)
282	               v.axilReadSlave.rdata(7 downto 0) := r.initSeqN;
283	            when 16#02# =>              -- ADDR (8)
284	               v.axilReadSlave.rdata(3 downto 0)   := r.appRssiParam.version;
285	               v.axilReadSlave.rdata(19 downto 16) := negRssiParam.version;
286	            when 16#03# =>              -- ADDR (12)
287	               v.axilReadSlave.rdata(7 downto 0)   := r.appRssiParam.maxOutsSeg;
288	               v.axilReadSlave.rdata(23 downto 16) := negRssiParam.maxOutsSeg;
289	            when 16#04# =>              -- ADDR (16)
290	               v.axilReadSlave.rdata(15 downto 0)  := r.appRssiParam.maxSegSize;
291	               v.axilReadSlave.rdata(31 downto 16) := negRssiParam.maxSegSize;
292	            when 16#05# =>              -- ADDR (20)
293	               v.axilReadSlave.rdata(15 downto 0)  := r.appRssiParam.retransTout;
294	               v.axilReadSlave.rdata(31 downto 16) := negRssiParam.retransTout;
295	            when 16#06# =>              -- ADDR (24)
296	               v.axilReadSlave.rdata(15 downto 0)  := r.appRssiParam.cumulAckTout;
297	               v.axilReadSlave.rdata(31 downto 16) := negRssiParam.cumulAckTout;
298	            when 16#07# =>              -- ADDR (28)
299	               v.axilReadSlave.rdata(15 downto 0)  := r.appRssiParam.nullSegTout;
300	               v.axilReadSlave.rdata(31 downto 16) := negRssiParam.nullSegTout;
301	            when 16#08# =>              -- ADDR (32)
302	               v.axilReadSlave.rdata(7 downto 0)   := r.appRssiParam.maxRetrans;
303	               v.axilReadSlave.rdata(23 downto 16) := negRssiParam.maxRetrans;
304	            when 16#09# =>              -- ADDR (36)
305	               v.axilReadSlave.rdata(7 downto 0)   := r.appRssiParam.maxCumAck;
306	               v.axilReadSlave.rdata(23 downto 16) := negRssiParam.maxCumAck;
307	            when 16#0A# =>              -- ADDR (40)
308	               v.axilReadSlave.rdata(7 downto 0)   := r.appRssiParam.maxOutofseq;
309	               v.axilReadSlave.rdata(23 downto 16) := negRssiParam.maxOutofseq;
310	            when 16#0B# =>              -- ADDR (44)
311	               v.axilReadSlave.rdata(31 downto 0) := r.appRssiParam.connectionId;
312	            when 16#0C# =>              -- ADDR (48)
313	               v.axilReadSlave.rdata(31 downto 0) := negRssiParam.connectionId;
314	            when 16#10# =>              -- ADDR (64)
315	               v.axilReadSlave.rdata(status_i'range) := s_status;
316	            when 16#11# =>              -- ADDR (68)
317	               v.axilReadSlave.rdata(31 downto 0) := s_validCnt;
318	            when 16#12# =>              -- ADDR (72)
319	               v.axilReadSlave.rdata(31 downto 0) := s_dropCnt;
320	            when 16#13# =>              -- ADDR (76)
321	               v.axilReadSlave.rdata(31 downto 0) := s_resendCnt;
322	            when 16#14# =>              -- ADDR (80)
323	               v.axilReadSlave.rdata(31 downto 0) := s_reconCnt;
324	            when 16#15# =>
325	               v.axilReadSlave.rdata(31 downto 0) := frameRate_i(0);
326	            when 16#16# =>
327	               v.axilReadSlave.rdata(31 downto 0) := frameRate_i(1);
328	            when 16#17# =>
329	               v.axilReadSlave.rdata(31 downto 0) := bandwidth_i(0)(31 downto 0);
330	            when 16#18# =>
331	               v.axilReadSlave.rdata(31 downto 0) := bandwidth_i(0)(63 downto 32);
332	            when 16#19# =>
333	               v.axilReadSlave.rdata(31 downto 0) := bandwidth_i(1)(31 downto 0);
334	            when 16#1A# =>
335	               v.axilReadSlave.rdata(31 downto 0) := bandwidth_i(1)(63 downto 32);
336	            when 16#1B# =>
337	               v.axilReadSlave.rdata(7 downto 0)   := txTspState_i;
338	               v.axilReadSlave.rdata(11 downto 8)  := txAppState_i;
339	               v.axilReadSlave.rdata(15 downto 12) := txAckState_i;
340	               v.axilReadSlave.rdata(19 downto 16) := rxTspState_i;
341	               v.axilReadSlave.rdata(23 downto 20) := rxAppState_i;
342	               v.axilReadSlave.rdata(27 downto 24) := connState_i;
343	            when 16#1C# =>
344	               v.axilReadSlave.rdata(7 downto 0)   := txLastAckN_i;
345	               v.axilReadSlave.rdata(15 downto 8)  := rxSeqN_i;
346	               v.axilReadSlave.rdata(23 downto 16) := rxAckN_i;
347	               v.axilReadSlave.rdata(31 downto 24) := rxLastSeqN_i;
348	            when others =>
349	               axilReadResp := AXI_RESP_DECERR_C;
350	         end case;
351	         axiSlaveReadResponse(v.axilReadSlave, axilReadResp);
352	      end if;
353	
354	      -- Map to chksumEn
355	      v.appRssiParam.chksumEn(0) := v.control(3);
356	
357	      -- Outputs
358	      axilReadSlave  <= r.axilReadSlave;
359	      axilWriteSlave <= r.axilWriteSlave;
360	
361	      -- Reset
362	      if (axiRst_i = '1') then
363	         v := REG_INIT_C;
364	      end if;
365	
366	      -- Register the variable for next clock cycle
367	      rin <= v;
368	
369	   end process comb;
370	
371	   seq : process (axiClk_i) is
372	   begin
373	      if rising_edge(axiClk_i) then
374	         r <= rin after TPD_G;
375	      end if;
376	   end process seq;
377	
378	   U_status : entity surf.SynchronizerVector
379	      generic map (
380	         TPD_G         => TPD_G,
381	         BYPASS_SYNC_G => COMMON_CLK_G,
382	         WIDTH_G       => status_i'length)
383	      port map (
384	         clk     => devClk_i,
385	         dataIn  => status_i,
386	         dataOut => s_status);
387	
388	   U_validCnt : entity surf.SynchronizerFifo
389	      generic map (
390	         TPD_G        => TPD_G,
391	         COMMON_CLK_G => COMMON_CLK_G,
392	         DATA_WIDTH_G => validCnt_i'length)
393	      port map (
394	         wr_clk => devClk_i,
395	         din    => validCnt_i,
396	         rd_clk => axiClk_i,
397	         dout   => s_validCnt);
398	
399	   U_dropCnt : entity surf.SynchronizerFifo
400	      generic map (
401	         TPD_G        => TPD_G,
402	         COMMON_CLK_G => COMMON_CLK_G,
403	         DATA_WIDTH_G => dropCnt_i'length)
404	      port map (
405	         wr_clk => devClk_i,
406	         din    => dropCnt_i,
407	         rd_clk => axiClk_i,
408	         dout   => s_dropCnt);
409	
410	   U_resendCnt : entity surf.SynchronizerFifo
411	      generic map (
412	         TPD_G        => TPD_G,
413	         COMMON_CLK_G => COMMON_CLK_G,
414	         DATA_WIDTH_G => resendCnt_i'length)
415	      port map (
416	         wr_clk => devClk_i,
417	         din    => resendCnt_i,
418	         rd_clk => axiClk_i,
419	         dout   => s_resendCnt);
420	
421	   U_reconCnt : entity surf.SynchronizerFifo
422	      generic map (
423	         TPD_G        => TPD_G,
424	         COMMON_CLK_G => COMMON_CLK_G,
425	         DATA_WIDTH_G => reconCnt_i'length)
426	      port map (
427	         wr_clk => devClk_i,
428	         din    => reconCnt_i,
429	         rd_clk => axiClk_i,
430	         dout   => s_reconCnt);
431	
432	   U_SyncVecOut : entity surf.SynchronizerVector
433	      generic map (
434	         TPD_G         => TPD_G,
435	         BYPASS_SYNC_G => COMMON_CLK_G,
436	         WIDTH_G       => 5)
437	      port map (
438	         clk        => devClk_i,
439	         dataIn     => r.control,
440	         dataOut(0) => openRq_o,
441	         dataOut(1) => closeRq_o,
442	         dataOut(2) => mode_o,
443	         dataOut(3) => dummyBit,        -- appRssiParam_o.chksumEn(0)
444	         dataOut(4) => injectFault_o);
445	
446	   U_initSeqN : entity surf.SynchronizerVector
447	      generic map (
448	         TPD_G         => TPD_G,
449	         BYPASS_SYNC_G => COMMON_CLK_G,
450	         WIDTH_G       => 8)
451	      port map (
452	         clk     => devClk_i,
453	         dataIn  => r.initSeqN,
454	         dataOut => initSeqN_o);
455	
456	   U_RssiParamSync_In : entity surf.RssiParamSync
457	      generic map (
458	         TPD_G        => TPD_G,
459	         COMMON_CLK_G => COMMON_CLK_G)
460	      port map (
461	         clk         => devClk_i,
462	         rssiParam_i => negRssiParam_i,
463	         rssiParam_o => negRssiParam);
464	
465	   U_RssiParamSync_Out : entity surf.RssiParamSync
466	      generic map (
467	         TPD_G        => TPD_G,
468	         COMMON_CLK_G => COMMON_CLK_G)
469	      port map (
470	         clk         => devClk_i,
471	         rssiParam_i => r.appRssiParam,
472	         rssiParam_o => appRssiParam_o);
473	
474	end rtl;
475

