1	-------------------------------------------------------------------------------
2	-- Title      : RSSI Protocol: https://confluence.slac.stanford.edu/x/1IyfD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description:
7	--  Handles RSSI counters, timeouts, and statuses:
8	--  - Re-transmission timeout and request,
9	--  - NULL segment transmission (Client),
10	--  - NULL timeout detection (Server),
11	--  - Acknowledgment timeout and request,
12	--  - Valid segment counter,
13	--  - Dropped segment counter.
14	--
15	--  Status register:
16	--    statusReg_o(0) : Connection Active
17	--    statusReg_o(1) : Maximum retransmissions exceeded r.retransMax and
18	--    statusReg_o(2) : Null timeout reached (server) r.nullTout;
19	--    statusReg_o(3) : Error in acknowledgment mechanism
20	--    statusReg_o(4) : SSI Frame length too long
21	--    statusReg_o(5) : Connection to peer timed out
22	--    statusReg_o(6) : Client rejected the connection (parameters out of range)
23	--                     Server proposed new parameters (parameters out of range)
24	--    statusReg_o(7) : Local busy
25	--    statusReg_o(8) : Remote busy
26	-------------------------------------------------------------------------------
27	-- This file is part of 'SLAC Firmware Standard Library'.
28	-- It is subject to the license terms in the LICENSE.txt file found in the
29	-- top-level directory of this distribution and at:
30	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
31	-- No part of 'SLAC Firmware Standard Library', including this file,
32	-- may be copied, modified, propagated, or distributed except according to
33	-- the terms contained in the LICENSE.txt file.
34	-------------------------------------------------------------------------------
35	
36	library ieee;
37	use ieee.std_logic_1164.all;
38	use ieee.std_logic_unsigned.all;
39	use ieee.std_logic_arith.all;
40	
41	library surf;
42	use surf.StdRtlPkg.all;
43	use surf.RssiPkg.all;
44	
45	entity RssiMonitor is
46	   generic (
47	      TPD_G               : time     := 1 ns;
48	      TIMEOUT_UNIT_G      : real     := 1.0E-6;  -- us
49	      CLK_FREQUENCY_G     : real     := 100.0E6;
50	      SERVER_G            : boolean  := true;
51	      WINDOW_ADDR_SIZE_G  : positive := 7;
52	      STATUS_WIDTH_G      : positive := 8;
53	      CNT_WIDTH_G         : positive := 32;
54	      RETRANSMIT_ENABLE_G : boolean  := true
55	    --
56	      );
57	   port (
58	      clk_i : in sl;
59	      rst_i : in sl;
60	
61	      -- Connection FSM indicating active connection
62	      connActive_i : in sl;
63	
64	      -- Local Busy Flag
65	      localBusy_i : in sl;
66	
67	      -- Timeout and counter values
68	      rssiParam_i : in RssiParamType;
69	
70	      -- Flags from Rx module
71	      rxFlags_i : in FlagsType;
72	
73	      --
74	      rxLastSeqN_i   : in slv(7 downto 0);
75	      rxWindowSize_i : in integer range 1 to 2 ** (WINDOW_ADDR_SIZE_G);
76	
77	      -- Do not request resend if tx buffer empty
78	      txBufferEmpty_i : in sl;
79	
80	      -- Valid received packet
81	      rxValid_i : in sl;
82	      rxDrop_i  : in sl;
83	
84	      --
85	      ackHeadSt_i  : in sl;
86	      rstHeadSt_i  : in sl;
87	      dataHeadSt_i : in sl;
88	      nullHeadSt_i : in sl;
89	
90	      -- Internal Errors and Timeouts
91	      lenErr_i       : in sl;
92	      ackErr_i       : in sl;
93	      peerConnTout_i : in sl;
94	      paramReject_i  : in sl;
95	
96	      -- Packet transmission requests
97	      sndResend_o : out sl;
98	      sndNull_o   : out sl;
99	      sndAck_o    : out sl;
100	
101	      -- Connection close request
102	      closeRq_o : out sl;
103	
104	      -- Internal statuses
105	      statusReg_o : out slv(STATUS_WIDTH_G downto 0);
106	      dropCnt_o   : out slv(CNT_WIDTH_G-1 downto 0);
107	      validCnt_o  : out slv(CNT_WIDTH_G-1 downto 0);
108	      resendCnt_o : out slv(CNT_WIDTH_G-1 downto 0);
109	      reconCnt_o  : out slv(CNT_WIDTH_G-1 downto 0)
110	      );
111	end entity RssiMonitor;
112	
113	architecture rtl of RssiMonitor is
114	
115	   constant SAMPLES_PER_TIME_C      : integer := integer(TIMEOUT_UNIT_G * CLK_FREQUENCY_G);
116	   constant SAMPLES_PER_TIME_DIV3_C : integer := integer(TIMEOUT_UNIT_G * CLK_FREQUENCY_G)/3;
117	
118	   constant MAX_TOUT_CNT_C     : slv(rssiParam_i.retransTout'left + bitSize(SAMPLES_PER_TIME_C) downto 0)  := (others => '1');
119	   constant MAX_RETRANS_CNT_C  : slv(rssiParam_i.maxRetrans'left + bitSize(SAMPLES_PER_TIME_C) downto 0)   := (others => '1');
120	   constant MAX_NULL_CNT_C     : slv(rssiParam_i.nullSegTout'left + bitSize(SAMPLES_PER_TIME_C) downto 0)  := (others => '1');
121	   constant MAX_ACK_TOUT_CNT_C : slv(rssiParam_i.cumulAckTout'left + bitSize(SAMPLES_PER_TIME_C) downto 0) := (others => '1');
122	
123	   type RegType is record
124	      -- Retransmission
125	      retransToutCnt : slv(rssiParam_i.retransTout'left + bitSize(SAMPLES_PER_TIME_C) downto 0);
126	      sndResend      : sl;
127	      sndResendD1    : sl;
128	      retransCnt     : slv(rssiParam_i.maxRetrans'left + bitSize(SAMPLES_PER_TIME_C) downto 0);
129	      retransMax     : sl;
130	
131	      -- Null packet send/timeout
132	      nullToutCnt : slv(rssiParam_i.nullSegTout'left + bitSize(SAMPLES_PER_TIME_C) downto 0);
133	      sndNull     : sl;
134	      nullTout    : sl;
135	
136	      -- Ack packet cumulative/timeout
137	      ackToutCnt  : slv(rssiParam_i.cumulAckTout'left + bitSize(SAMPLES_PER_TIME_C) downto 0);
138	      lastAckSeqN : slv(7 downto 0);
139	      sndAck      : sl;
140	
141	      -- For detecting rising edge
142	      connActiveD1 : sl;
143	      localBusyD1  : sl;
144	
145	      --
146	      status    : slv(STATUS_WIDTH_G - 1 downto 0);
147	      validCnt  : slv(CNT_WIDTH_G - 1 downto 0);
148	      dropCnt   : slv(CNT_WIDTH_G - 1 downto 0);
149	      reconCnt  : slv(CNT_WIDTH_G - 1 downto 0);
150	      resendCnt : slv(CNT_WIDTH_G - 1 downto 0);
151	   --
152	   end record RegType;
153	
154	   constant REG_INIT_C : RegType := (
155	      -- Retransmission
156	      retransToutCnt => (others => '0'),
157	      sndResend      => '0',
158	      sndResendD1    => '0',
159	      retransCnt     => (others => '0'),
160	      retransMax     => '0',
161	
162	      -- Null packet send/timeout
163	      nullToutCnt => (others => '0'),
164	      sndnull     => '0',
165	      nullTout    => '0',
166	
167	      -- Ack packet cumulative/timeout
168	      ackToutCnt  => (others => '0'),
169	      lastAckSeqN => (others => '0'),
170	      sndAck      => '0',
171	
172	      -- For detecting rising edge
173	      connActiveD1 => '0',
174	      localBusyD1  => '0',
175	
176	      -- Statuses
177	      status    => (others => '0'),
178	      validCnt  => (others => '0'),
179	      dropCnt   => (others => '0'),
180	      reconCnt  => (others => '0'),
181	      resendCnt => (others => '0')
182	      );
183	
184	   signal r        : RegType := REG_INIT_C;
185	   signal rin      : RegType;
186	   signal s_status : slv(STATUS_WIDTH_G - 1 downto 0);
187	--
188	begin
189	   -- Status assignment
190	   s_status(0) <= r.retransMax and r.sndResend and not r.sndResendD1;
191	   s_status(1) <= r.nullTout;
192	   s_status(2) <= ackErr_i;
193	   s_status(3) <= lenErr_i;
194	   s_status(4) <= peerConnTout_i;
195	   s_status(5) <= paramReject_i;
196	   s_status(6) <= localBusy_i;
197	   s_status(7) <= rxFlags_i.busy;       -- Remote busy
198	
199	   comb : process (ackHeadSt_i, connActive_i, dataHeadSt_i, localBusy_i,
200	                   nullHeadSt_i, r, rssiParam_i, rstHeadSt_i, rst_i, rxDrop_i,
201	                   rxFlags_i, rxLastSeqN_i, rxValid_i, rxWindowSize_i,
202	                   s_status, txBufferEmpty_i) is
203	      variable v : RegType;
204	   begin
205	      v := r;
206	
207	      -- DFF for rising edge detection
208	      v.connActiveD1 := connActive_i;
209	      v.localBusyD1  := localBusy_i;
210	
211	      -- /////////////////////////////////////////////////////////
212	      ------------------------------------------------------------
213	      -- Retransmission timeout
214	      ------------------------------------------------------------
215	      -- /////////////////////////////////////////////////////////
216	
217	      -- Retransmission Timeout counter
218	      if (connActive_i = '0' or
219	          r.sndResend = '1' or
220	          rxFlags_i.busy = '1' or
221	          dataHeadSt_i = '1' or
222	          rstHeadSt_i = '1' or
223	          nullHeadSt_i = '1' or
224	          txBufferEmpty_i = '1' or
225	          RETRANSMIT_ENABLE_G = false   -- Disable retransmissions
226	          ) then
227	         v.retransToutCnt := (others => '0');
228	      elsif (r.retransToutCnt /= MAX_TOUT_CNT_C) then
229	         v.retransToutCnt := r.retransToutCnt+1;
230	      end if;
231	
232	      -- Resend request SRFF
233	      if (connActive_i = '0' or
234	          rxFlags_i.busy = '1' or
235	          dataHeadSt_i = '1' or
236	          rstHeadSt_i = '1' or
237	          nullHeadSt_i = '1' or
238	          txBufferEmpty_i = '1'
239	          ) then
240	         v.sndResend := '0';
241	      elsif (r.retransToutCnt >= (conv_integer(rssiParam_i.retransTout)*SAMPLES_PER_TIME_C)) then
242	         v.sndResend := '1';
243	
244	      end if;
245	
246	      -- Pipeline sndResend for edge detection
247	      v.sndResendD1 := r.sndResend;
248	
249	      -- /////////////////////////////////////////////////////////
250	      ------------------------------------------------------------
251	      -- Retransmission counter
252	      ------------------------------------------------------------
253	      -- /////////////////////////////////////////////////////////
254	      -- Counter of consecutive retransmissions
255	      -- Reset when connection is broken or a valid ACK is received
256	      if (connActive_i = '0' or
257	          (rxValid_i = '1' and rxFlags_i.ack = '1')
258	          ) then
259	         v.retransCnt := (others => '0');
260	      elsif (r.sndResend = '1' and r.sndResendD1 = '0') then  -- Rising edge
261	         if (r.retransCnt /= MAX_RETRANS_CNT_C) then
262	            v.retransCnt := r.retransCnt+1;
263	         end if;
264	      end if;
265	
266	      -- Retransmission exceeded close connection request SRFF
267	      if (connActive_i = '0' or
268	          (rxValid_i = '1' and rxFlags_i.ack = '1')
269	          ) then
270	         v.retransMax := '0';
271	      elsif (r.retransCnt >= rssiParam_i.maxRetrans) then
272	         v.retransMax := '1';
273	      end if;
274	
275	      -- /////////////////////////////////////////////////////////
276	      ------------------------------------------------------------
277	      -- Null Segment transmit/timeout
278	      ------------------------------------------------------------
279	      -- /////////////////////////////////////////////////////////
280	
281	      -- Null Segment transmission (Client)
282	      if (SERVER_G = false) then
283	         -- Null transmission counter
284	         if (connActive_i = '0' or
285	             dataHeadSt_i = '1' or
286	             rstHeadSt_i = '1' or
287	             nullHeadSt_i = '1' or
288	             ackHeadSt_i = '1' or
289	             RETRANSMIT_ENABLE_G = false  -- Disable null packet transmission
290	             ) then
291	            v.nullToutCnt := (others => '0');
292	         elsif (r.nullToutCnt /= MAX_NULL_CNT_C) then
293	            v.nullToutCnt := r.nullToutCnt+1;
294	         end if;
295	
296	         -- Null request SRFF
297	         if (connActive_i = '0' or
298	             dataHeadSt_i = '1' or
299	             rstHeadSt_i = '1' or
300	             nullHeadSt_i = '1') then
301	            v.sndNull := '0';
302	         elsif (r.nullToutCnt >= (conv_integer(rssiParam_i.nullSegTout) * SAMPLES_PER_TIME_DIV3_C)) then  -- send null segments if timeout/2 reached
303	            v.sndNull := '1';
304	         end if;
305	
306	         -- Timeout not applicable
307	         v.nullTout := '0';
308	
309	      -- Null timeout (Server)
310	      else
311	         -- Null timeout counter
312	         if (connActive_i = '0' or
313	             (rxValid_i = '1' and rxFlags_i.data = '1') or
314	             (rxValid_i = '1' and rxFlags_i.nul = '1') or
315	             (rxValid_i = '1' and rxFlags_i.ack = '1') or
316	             (rxValid_i = '1' and rxFlags_i.busy = '1') or
317	             RETRANSMIT_ENABLE_G = false  -- Disable null timeout
318	             ) then
319	            v.nullToutCnt := (others => '0');
320	         else
321	            v.nullToutCnt := r.nullToutCnt+1;
322	         end if;
323	
324	         -- Null timeout SRFF
325	         if (connActive_i = '0') then
326	            v.nullTout := '0';
327	         elsif (r.nullToutCnt >= (conv_integer(rssiParam_i.nullSegTout) * SAMPLES_PER_TIME_C)) then
328	            v.nullTout := '1';
329	         end if;
330	
331	      end if;
332	
333	      -- /////////////////////////////////////////////////////////
334	      ------------------------------------------------------------
335	      -- Acknowledgment cumulative/timeout
336	      ------------------------------------------------------------
337	      -- /////////////////////////////////////////////////////////
338	
339	      -- Ack seqN registering when it is sent
340	      if (connActive_i = '0') then
341	         v.lastAckSeqN := rxLastSeqN_i;
342	      elsif (
343	         ackHeadSt_i = '1' or
344	         dataHeadSt_i = '1' or
345	         rstHeadSt_i = '1' or
346	         nullHeadSt_i = '1'
347	         ) then
348	         v.lastAckSeqN := rxLastSeqN_i;
349	      else
350	         v.lastAckSeqN := r.lastAckSeqN;
351	      end if;
352	
353	      -- Timeout counter
354	      if (connActive_i = '0' or
355	          ackHeadSt_i = '1' or
356	          dataHeadSt_i = '1' or
357	          rstHeadSt_i = '1' or
358	          nullHeadSt_i = '1' or
359	          (rxLastSeqN_i - r.lastAckSeqN) = 0
360	          ) then
361	         v.ackToutCnt := (others => '0');
362	      elsif ((rxLastSeqN_i - r.lastAckSeqN) > 0 and (rxLastSeqN_i - r.lastAckSeqN) <= rxWindowSize_i) or (localBusy_i = '1') then
363	         if (r.ackToutCnt /= MAX_ACK_TOUT_CNT_C) then
364	            v.ackToutCnt := r.ackToutCnt+1;
365	         end if;
366	      end if;
367	
368	      -- Ack packet request SRFF
369	      if (connActive_i = '0' or
370	          ackHeadSt_i = '1' or
371	          dataHeadSt_i = '1' or
372	          nullHeadSt_i = '1' or
373	          rstHeadSt_i = '1'
374	          ) then
375	         v.sndAck := '0';
376	
377	      -- Timeout acknowledgment request
378	      elsif (r.ackToutCnt >= (conv_integer(rssiParam_i.cumulAckTout)* SAMPLES_PER_TIME_C)) then
379	         v.sndAck := '1';
380	
381	      -- Cumulative acknowledgment request
382	      elsif ((rxLastSeqN_i - r.lastAckSeqN) >= rssiParam_i.maxCumAck) then
383	         v.sndAck := '1';
384	
385	      -- Null segment ACK as soon as NUL received
386	      elsif (rxValid_i = '1' and rxFlags_i.nul = '1') then
387	         v.sndAck := '1';
388	      end if;
389	
390	      -- Send a ACK if there is a local busy event
391	      if (localBusy_i = '1' and r.localBusyD1 = '0') then
392	         v.sndAck := '1';
393	      end if;
394	
395	      -- /////////////////////////////////////////////////////////
396	      ------------------------------------------------------------
397	      -- Status register and valid and drop counters
398	      ------------------------------------------------------------
399	      -- /////////////////////////////////////////////////////////
400	
401	      -- Register statuses until new connection is established
402	      if (connActive_i = '1' and r.connActiveD1 = '0') then
403	         v.status := (others => '0');
404	      elsif (s_status /= (s_status'range => '0')) then
405	         v.status := r.status or s_status;
406	      end if;
407	
408	      -- Count valid packets
409	      if (connActive_i = '1' and r.connActiveD1 = '0') then
410	         v.validCnt := (others => '0');
411	      elsif (rxValid_i = '1') then
412	         v.validCnt := r.validCnt+1;
413	      end if;
414	
415	      -- Count dropped packets
416	      if (connActive_i = '1' and r.connActiveD1 = '0') then
417	         v.dropCnt := (others => '0');
418	      elsif (rxDrop_i = '1') then
419	         v.dropCnt := r.dropCnt+1;
420	      end if;
421	
422	      -- Count all retransmissions within the active connection
423	      if (connActive_i = '1' and r.connActiveD1 = '0') then
424	         v.resendCnt := (others => '0');
425	      elsif (r.sndResend = '1' and r.sndResendD1 = '0') then  -- Rising edge
426	         v.resendCnt := r.resendCnt+1;
427	      end if;
428	
429	      -- Count all reconnections from reset
430	      if (connActive_i = '1' and r.connActiveD1 = '0') then
431	         v.reconCnt := r.reconCnt+1;
432	      end if;
433	
434	      -- /////////////////////////////////////////////////////////
435	      if (rst_i = '1') then
436	         v := REG_INIT_C;
437	      end if;
438	
439	      rin <= v;
440	   -----------------------------------------------------------
441	   end process comb;
442	
443	   seq : process (clk_i) is
444	   begin
445	      if (rising_edge(clk_i)) then
446	         r <= rin after TPD_G;
447	      end if;
448	   end process seq;
449	   ---------------------------------------------------------------------
450	   sndResend_o <= r.sndResend and not r.retransMax;  -- Request retransmission if max retransmissions not reached
451	   sndNull_o   <= r.sndNull;
452	   sndAck_o    <= r.sndAck;
453	   closeRq_o   <= (r.retransMax and r.sndResend and not r.sndResendD1) or  -- Close connection when exceeded resend is requested
454	                r.nullTout or           -- Close connection when null timeouts
455	                ackErr_i or             -- Close if acknowledgment error occurs
456	                lenErr_i;      -- Close if SSI input frame length error occurs
457	   statusReg_o <= r.status & connActive_i;
458	   dropCnt_o   <= r.dropCnt;
459	   validCnt_o  <= r.validCnt;
460	   resendCnt_o <= r.resendCnt;
461	   reconCnt_o  <= r.reconCnt;
462	---------------------------------------------------------------------
463	end architecture rtl;
464

