1	-------------------------------------------------------------------------------
2	-- Title      : RSSI Protocol: https://confluence.slac.stanford.edu/x/1IyfD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: Combines and decodes the header values from input parameters headerValues_i
7	--              Header is selected by xxxHeadSt_i and addressed by addr_i
8	--              Outputs the addressed headerData_o and headerLength_o values with 1 Clock Cycle delay
9	--              Outputs (oth=>'0')If no header is addressed
10	-------------------------------------------------------------------------------
11	-- This file is part of 'SLAC Firmware Standard Library'.
12	-- It is subject to the license terms in the LICENSE.txt file found in the
13	-- top-level directory of this distribution and at:
14	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
15	-- No part of 'SLAC Firmware Standard Library', including this file,
16	-- may be copied, modified, propagated, or distributed except according to
17	-- the terms contained in the LICENSE.txt file.
18	-------------------------------------------------------------------------------
19	
20	library ieee;
21	use ieee.std_logic_1164.all;
22	use ieee.std_logic_unsigned.all;
23	use ieee.std_logic_arith.all;
24	
25	
26	library surf;
27	use surf.StdRtlPkg.all;
28	use surf.RssiPkg.all;
29	use ieee.math_real.all;
30	
31	entity RssiHeaderReg is
32	   generic (
33	      TPD_G : time := 1 ns;
34	
35	      SYN_HEADER_SIZE_G  : natural := 24;
36	      ACK_HEADER_SIZE_G  : natural := 8;
37	      EACK_HEADER_SIZE_G : natural := 8;
38	      RST_HEADER_SIZE_G  : natural := 8;
39	      NULL_HEADER_SIZE_G : natural := 8;
40	      DATA_HEADER_SIZE_G : natural := 8
41	      );
42	   port (
43	      clk_i : in sl;
44	      rst_i : in sl;
45	
46	      -- Header control inputs (must hold values while reading header)
47	      synHeadSt_i  : in sl;
48	      rstHeadSt_i  : in sl;
49	      dataHeadSt_i : in sl;
50	      nullHeadSt_i : in sl;
51	      ackHeadSt_i  : in sl;
52	      busyHeadSt_i : in sl;
53	      --eackHeadSt_i : in  sl;
54	
55	      -- Ack sequence number valid
56	      ack_i : in sl;
57	
58	      -- Header values
59	      txSeqN_i : in slv(7 downto 0);  -- Sequence number of the current packet
60	      rxAckN_i : in slv(7 downto 0);  -- Acknowledgment number of the received packet handled by receiver
61	
62	      -- Negotiated or from GENERICS
63	      headerValues_i : in RssiParamType;
64	
65	      -- Out of order sequence numbers from received EACK packet
66	      --eackSeqnArr_i  : in Slv16Array(0 to integer(ceil(real(MAX_OUT_OF_SEQUENCE_G)/2.0))-1);
67	      --eackN_i        : in natural;
68	
69	      addr_i         : in  slv(7 downto 0);
70	      headerData_o   : out slv((RSSI_WORD_WIDTH_C * 8)-1 downto 0);
71	      ready_o        : out sl;
72	      headerLength_o : out positive
73	      );
74	end entity RssiHeaderReg;
75	
76	architecture rtl of RssiHeaderReg is
77	
78	   type RegType is record
79	      headerData : slv(RSSI_WORD_WIDTH_C*8-1 downto 0);
80	      rdy        : sl;
81	
82	      -- Registered header parameters (so they don't change during the checksum calculation)
83	      ack    : sl;
84	      busy   : sl;
85	      txSeqN : slv(7 downto 0);
86	      rxAckN : slv(7 downto 0);
87	
88	   end record RegType;
89	
90	   constant REG_INIT_C : RegType := (
91	      headerData => (others => '0'),
92	      rdy        => '0',
93	
94	      ack    => '0',
95	      busy   => '0',
96	      txSeqN => (others => '0'),
97	      rxAckN => (others => '0')
98	      );
99	
100	   signal r   : RegType := REG_INIT_C;
101	   signal rin : RegType;
102	
103	   signal addrInt : integer;
104	
105	begin
106	
107	   -- Convert address to integer
108	   addrInt <= conv_integer(addr_i);
109	
110	   --
111	   comb : process (ackHeadSt_i, ack_i, addrInt, busyHeadSt_i, dataHeadSt_i,
112	                   headerValues_i, nullHeadSt_i, r, rstHeadSt_i, rst_i,
113	                   rxAckN_i, synHeadSt_i, txSeqN_i) is
114	
115	      variable v : RegType;
116	
117	   begin
118	      v := r;
119	
120	      --
121	      if (synHeadSt_i = '1') then
122	         headerLength_o <= SYN_HEADER_SIZE_G/RSSI_WORD_WIDTH_C;
123	         case addrInt is
124	            when 16#00# =>
125	               v.headerData := "1" & r.ack & "000000" & toSlv(SYN_HEADER_SIZE_G, 8) &
126	                               txSeqN_i & r.rxAckN &
127	                               headerValues_i.version & '1' & headerValues_i.chksumEn & "00" & headerValues_i.maxOutsSeg &
128	                               headerValues_i.maxSegSize;
129	               v.rdy := '1';
130	            when 16#01# =>
131	               v.headerData := headerValues_i.retransTout &
132	                               headerValues_i.cumulAckTout &
133	                               headerValues_i.nullSegTout &
134	                               headerValues_i.maxRetrans & headerValues_i.maxCumAck;
135	               v.rdy := '1';
136	            when 16#02# =>
137	               v.headerData := headerValues_i.maxOutofseq & headerValues_i.timeoutUnit &
138	                               headerValues_i.connectionId(31 downto 16) &
139	                               headerValues_i.connectionId(15 downto 0) &
140	                               x"00" & x"00";  -- Place for checksum
141	               v.rdy := '1';
142	            when others =>
143	               v.headerData := (others => '0');
144	               v.rdy        := '0';
145	         end case;
146	      elsif (rstHeadSt_i = '1') then
147	         headerLength_o <= RST_HEADER_SIZE_G/RSSI_WORD_WIDTH_C;
148	         case addrInt is
149	
150	            when 16#00# =>
151	               v.headerData := "0001000" & r.busy & toSlv(RST_HEADER_SIZE_G, 8) &
152	                               txSeqN_i & r.rxAckN &
153	                               x"00" & x"00" &  -- Reserved
154	                               x"00" & x"00";   -- Place for checksum
155	               v.rdy := '1';
156	            when others =>
157	               v.headerData := (others => '0');
158	               v.rdy        := '0';
159	         end case;
160	      elsif (dataHeadSt_i = '1') then
161	         headerLength_o <= DATA_HEADER_SIZE_G/RSSI_WORD_WIDTH_C;
162	         case addrInt is
163	            when 16#00# =>
164	               v.headerData := "0" & r.ack & "00000" & r.busy & toSlv(DATA_HEADER_SIZE_G, 8) &
165	                               txSeqN_i & r.rxAckN &
166	                               x"00" & x"00" &  -- Reserved
167	                               x"00" & x"00";   -- Place for checksum
168	               v.rdy := '1';
169	            when others =>
170	               v.rdy        := '0';
171	               v.headerData := (others => '0');
172	         end case;
173	      elsif (ackHeadSt_i = '1') then
174	         headerLength_o <= DATA_HEADER_SIZE_G/RSSI_WORD_WIDTH_C;
175	         case addrInt is
176	            when 16#00# =>
177	               v.headerData := "0100000" & r.busy & toSlv(DATA_HEADER_SIZE_G, 8) &
178	                               txSeqN_i & r.rxAckN &
179	                               x"00" & x"00" &  -- Reserved
180	                               x"00" & x"00";   -- Place for checksum
181	               v.rdy := '1';
182	            when others =>
183	               v.rdy        := '0';
184	               v.headerData := (others => '0');
185	         end case;
186	
187	
188	      elsif (nullHeadSt_i = '1') then
189	         headerLength_o <= NULL_HEADER_SIZE_G/RSSI_WORD_WIDTH_C;
190	         case addrInt is
191	            when 16#00# =>
192	               v.headerData := "0" & r.ack & "00100" & r.busy & toSlv(NULL_HEADER_SIZE_G, 8) &
193	                               txSeqN_i & r.rxAckN &
194	                               x"00" & x"00" &  -- Reserved
195	                               x"00" & x"00";   -- Place for checksum
196	               v.rdy := '1';
197	            when others =>
198	               v.rdy        := '1';
199	               v.headerData := (others => '0');
200	         end case;
201	      -- elsif (eackHeadSt_i = '1') then
202	      --    case addrInt is
203	      --       when 16#00# =>
204	      --         v.headerData := "01100000" & toSlv(EACK_HEADER_SIZE_G+r.eackN, 8);
205	      --       when 16#01# =>
206	      --         v.headerData := txSeqN_i & r.rxAckN;
207	      --       when 16#02# to (2+MAX_OUT_OF_ORDER_G-1) =>
208	      --         v.headerData := r.eackSeqnArr(addrInt-2);
209	      --       when others =>
210	      --         v.headerData := (others=> '0');
211	      --    end case;
212	      else
213	         -- Register parameters when out of headers
214	         v.ack          := ack_i;
215	         v.txSeqN       := txSeqN_i;
216	         v.rxAckN       := rxAckN_i;
217	         v.busy         := busyHeadSt_i;
218	         --
219	         headerLength_o <= 1;
220	         v.headerData   := (others => '0');
221	         v.rdy          := '0';
222	      end if;
223	
224	      if (rst_i = '1') then
225	         v := REG_INIT_C;
226	      end if;
227	
228	      rin <= v;
229	   -----------------------------------------------------------
230	   end process comb;
231	
232	   seq : process (clk_i) is
233	   begin
234	      if (rising_edge(clk_i)) then
235	         r <= rin after TPD_G;
236	      end if;
237	   end process seq;
238	   ---------------------------------------------------------------------
239	   -- Output assignment
240	   headerData_o <= r.headerData;
241	   ready_o      <= r.rdy;
242	---------------------------------------------------------------------
243	end architecture rtl;
